s';\nexport { default as LucideWheat, default as Wheat, default as WheatIcon } from './icons/wheat.js';\nexport { default as LucideWholeWord, default as WholeWord, default as WholeWordIcon } from './icons/whole-word.js';\nexport { default as LucideWifiHigh, default as WifiHigh, default as WifiHighIcon } from './icons/wifi-high.js';\nexport { default as LucideWifiLow, default as WifiLow, default as WifiLowIcon } from './icons/wifi-low.js';\nexport { default as LucideWifiOff, default as WifiOff, default as WifiOffIcon } from './icons/wifi-off.js';\nexport { default as LucideWifiZero, default as WifiZero, default as WifiZeroIcon } from './icons/wifi-zero.js';\nexport { default as LucideWifi, default as Wifi, default as WifiIcon } from './icons/wifi.js';\nexport { default as LucideWindArrowDown, default as WindArrowDown, default as WindArrowDownIcon } from './icons/wind-arrow-down.js';\nexport { default as LucideWind, default as Wind, default as WindIcon } from './icons/wind.js';\nexport { default as LucideWineOff, default as WineOff, default as WineOffIcon } from './icons/wine-off.js';\nexport { default as LucideWine, default as Wine, default as WineIcon } from './icons/wine.js';\nexport { default as LucideWorkflow, default as Workflow, default as WorkflowIcon } from './icons/workflow.js';\nexport { default as LucideWorm, default as Worm, default as WormIcon } from './icons/worm.js';\nexport { default as LucideWrapText, default as WrapText, default as WrapTextIcon } from './icons/wrap-text.js';\nexport { default as LucideWrench, default as Wrench, default as WrenchIcon } from './icons/wrench.js';\nexport { default as LucideX, default as X, default as XIcon } from './icons/x.js';\nexport { default as LucideYoutube, default as Youtube, default as YoutubeIcon } from './icons/youtube.js';\nexport { default as LucideZapOff, default as ZapOff, default as ZapOffIcon } from './icons/zap-off.js';\nexport { default as LucideZap, default as Zap, default as ZapIcon } from './icons/zap.js';\nexport { default as LucideZoomIn, default as ZoomIn, default as ZoomInIcon } from './icons/zoom-in.js';\nexport { default as LucideZoomOut, default as ZoomOut, default as ZoomOutIcon } from './icons/zoom-out.js';\nexport { default as ArrowDown01, default as ArrowDown01Icon, default as LucideArrowDown01 } from './icons/arrow-down-0-1.js';\nexport { default as ArrowDown10, default as ArrowDown10Icon, default as LucideArrowDown10 } from './icons/arrow-down-1-0.js';\nexport { default as ArrowUp01, default as ArrowUp01Icon, default as LucideArrowUp01 } from './icons/arrow-up-0-1.js';\nexport { default as ArrowUp10, default as ArrowUp10Icon, default as LucideArrowUp10 } from './icons/arrow-up-1-0.js';\nexport { default as createLucideIcon } from './createLucideIcon.js';\nexport { default as Icon } from './Icon.js';\n//# sourceMappingURL=lucide-react.js.map\n","import React from 'react';\nimport clsx from 'clsx';\nimport * as Icons from 'lucide-react';\n\n/**\n * Button Component\n */\nconst Button = ({\n  text,\n  url,\n  link,\n  type = 'button',\n  variant = 'primary',\n  size = 'medium',\n  icon,\n  iconPosition = 'left',\n  openInNewTab = false,\n  scrollTarget,\n  onClick,\n  disabled = false,\n  style = {},\n  className = '',\n}) => {\n  // Support Strapi's \"link\" field as well as legacy \"url\"\n  const resolvedUrl = url || link;\n  const IconComponent = icon && Icons[icon];\n\n  const sizeStyles = {\n    small: { padding: '0.5rem 1rem', fontSize: '0.875rem' },\n    medium: { padding: '0.75rem 1.5rem', fontSize: '1rem' },\n    large: { padding: '1rem 2rem', fontSize: '1.125rem' },\n  };\n\n  const variantStyles = {\n    primary: {\n      background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)',\n      color: '#fff',\n      border: 'none',\n    },\n    secondary: {\n      background: '#fff',\n      color: '#4f46e5',\n      border: '2px solid #4f46e5',\n    },\n    outline: {\n      background: 'transparent',\n      color: '#fff',\n      border: '2px solid #fff',\n    },\n    ghost: {\n      background: 'transparent',\n      color: '#4f46e5',\n      border: 'none',\n    },\n    danger: {\n      background: '#ef4444',\n      color: '#fff',\n      border: 'none',\n    },\n    success: {\n      background: '#22c55e',\n      color: '#fff',\n      border: 'none',\n    },\n  };\n\n  const buttonStyle = {\n    display: 'inline-flex',\n    alignItems: 'center',\n    justifyContent: 'center',\n    gap: '0.5rem',\n    borderRadius: '8px',\n    fontWeight: 600,\n    cursor: disabled ? 'not-allowed' : 'pointer',\n    opacity: disabled ? 0.6 : 1,\n    transition: 'all 0.2s',\n    textDecoration: 'none',\n    ...sizeStyles[size],\n    ...variantStyles[variant],\n    ...style,\n  };\n\n  const handleClick = (e) => {\n    if (type === 'scroll' && scrollTarget) {\n      e.preventDefault();\n      const element = document.querySelector(scrollTarget);\n      if (element) {\n        element.scrollIntoView({ behavior: 'smooth' });\n      }\n    }\n    onClick?.(e);\n  };\n\n  const content = (\n    <>\n      {IconComponent && iconPosition === 'left' && <IconComponent size={18} />}\n      <span>{text}</span>\n      {IconComponent && iconPosition === 'right' && <IconComponent size={18} />}\n    </>\n  );\n\n  if (resolvedUrl) {\n    return (\n      <a\n        href={resolvedUrl}\n        target={openInNewTab ? '_blank' : undefined}\n        rel={openInNewTab ? 'noopener noreferrer' : undefined}\n        className={clsx('button', `button-${variant}`, className)}\n        style={buttonStyle}\n        onClick={handleClick}\n      >\n        {content}\n      </a>\n    );\n  }\n\n  return (\n    <button\n      type={type === 'submit' ? 'submit' : 'button'}\n      className={clsx('button', `button-${variant}`, className)}\n      style={buttonStyle}\n      onClick={handleClick}\n      disabled={disabled}\n    >\n      {content}\n    </button>\n  );\n};\n\nexport default Button;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport Button from '../forms/Button';\n\n/**\n * Hero Section Component\n *\n * Accepts props directly from Strapi's layout.hero component:\n *   title, subtitle, cta, secondaryCta, variant, gradientFrom, gradientTo, minHeight\n *\n * Also supports legacy props: primaryButton, secondaryButton, backgroundImage, etc.\n */\nconst Hero = ({\n  title,\n  subtitle,\n  // Strapi props\n  cta,\n  secondaryCta,\n  variant = 'gradient',\n  gradientFrom = '#6366F1',\n  gradientTo = '#0EA5E9',\n  minHeight = '80vh',\n  // Legacy props\n  primaryButton,\n  secondaryButton,\n  backgroundImage,\n  backgroundVideo,\n  alignment = 'center',\n  height,\n  overlay = true,\n  overlayColor,\n  textColor = '#ffffff',\n  className = '',\n}) => {\n  // Resolve buttons: prefer Strapi cta/secondaryCta, fall back to legacy\n  const resolvedPrimary = cta || primaryButton;\n  const resolvedSecondary = secondaryCta || secondaryButton;\n\n  // Resolve height\n  const heightMap = { small: '40vh', medium: '60vh', large: '80vh', fullScreen: '100vh' };\n  const resolvedMinHeight = height ? (heightMap[height] || height) : minHeight;\n\n  // Build background based on variant\n  // NOTE: React inline styles don't handle \"background\" shorthand with gradients.\n  // Use backgroundImage for gradients and backgroundColor for solid colors.\n  const variantStyles = {\n    gradient: {\n      backgroundImage: `linear-gradient(135deg, ${gradientFrom}, ${gradientTo})`,\n    },\n    dark: {\n      backgroundColor: '#111827',\n    },\n    light: {\n      backgroundColor: '#f8fafc',\n      color: '#111827',\n    },\n    wave: {\n      backgroundImage: `linear-gradient(135deg, ${gradientFrom}, ${gradientTo})`,\n    },\n    split: {\n      backgroundColor: '#ffffff',\n      color: '#111827',\n    },\n  };\n\n  const variantStyle = variantStyles[variant] || variantStyles.gradient;\n  const resolvedTextColor = variantStyle.color || textColor;\n\n  const bgImageUrl = backgroundImage?.data?.attributes?.url || backgroundImage?.url;\n\n  const containerStyle = {\n    position: 'relative',\n    minHeight: resolvedMinHeight,\n    display: 'flex',\n    alignItems: 'center',\n    justifyContent: 'center',\n    ...variantStyle,\n    ...(bgImageUrl ? {\n      backgroundImage: `url(${bgImageUrl})`,\n      backgroundSize: 'cover',\n      backgroundPosition: 'center',\n    } : {}),\n    color: resolvedTextColor,\n  };\n\n  const showOverlay = overlay && bgImageUrl;\n  const resolvedOverlayColor = overlayColor || 'rgba(0,0,0,0.5)';\n\n  const contentStyle = {\n    position: 'relative',\n    zIndex: 1,\n    textAlign: alignment,\n    maxWidth: '900px',\n    padding: '2rem',\n  };\n\n  return (\n    <section className={clsx('hero-section', `hero-${variant}`, className)} style={containerStyle}>\n      {backgroundVideo && (\n        <video\n          autoPlay loop muted playsInline\n          style={{\n            position: 'absolute', top: 0, left: 0,\n            width: '100%', height: '100%', objectFit: 'cover',\n          }}\n        >\n          <source src={backgroundVideo} type=\"video/mp4\" />\n        </video>\n      )}\n\n      {showOverlay && (\n        <div style={{\n          position: 'absolute', top: 0, left: 0, right: 0, bottom: 0,\n          background: resolvedOverlayColor,\n        }} />\n      )}\n\n      <div className=\"hero-content\" style={contentStyle}>\n        {title && (\n          <h1 style={{\n            fontSize: 'clamp(2rem, 5vw, 4rem)',\n            fontWeight: 700,\n            marginBottom: '1rem',\n            lineHeight: 1.2,\n          }}>\n            {title}\n          </h1>\n        )}\n\n        {subtitle && (\n          <p style={{\n            fontSize: 'clamp(1rem, 2vw, 1.5rem)',\n            opacity: 0.9,\n            marginBottom: '2rem',\n            lineHeight: 1.6,\n          }}>\n            {subtitle}\n          </p>\n        )}\n\n        {(resolvedPrimary || resolvedSecondary) && (\n          <div style={{\n            display: 'flex',\n            gap: '1rem',\n            justifyContent: alignment,\n            flexWrap: 'wrap',\n          }}>\n            {resolvedPrimary && (\n              <Button\n                text={resolvedPrimary.text || resolvedPrimary.label}\n                link={resolvedPrimary.link || resolvedPrimary.href}\n                variant={resolvedPrimary.style || 'primary'}\n              />\n            )}\n            {resolvedSecondary && (\n              <Button\n                text={resolvedSecondary.text || resolvedSecondary.label}\n                link={resolvedSecondary.link || resolvedSecondary.href}\n                variant={resolvedSecondary.style || 'outline'}\n              />\n            )}\n          </div>\n        )}\n      </div>\n    </section>\n  );\n};\n\nexport default Hero;\n","import React from 'react';\nimport clsx from 'clsx';\nimport Button from '../forms/Button';\n\n/**\n * CTA Banner Section Component\n */\nconst CTABanner = ({\n  title,\n  subtitle,\n  backgroundColor = '#4f46e5',\n  gradientFrom,\n  gradientTo,\n  textColor = '#ffffff',\n  button,\n  alignment = 'center',\n  className = '',\n}) => {\n  const containerStyle = {\n    ...(gradientFrom && gradientTo\n      ? { backgroundImage: `linear-gradient(135deg, ${gradientFrom}, ${gradientTo})` }\n      : { backgroundColor }),\n    color: textColor,\n    padding: '4rem 2rem',\n    textAlign: alignment,\n  };\n\n  const contentStyle = {\n    maxWidth: '800px',\n    margin: alignment === 'center' ? '0 auto' : undefined,\n  };\n\n  return (\n    <section className={clsx('cta-banner-section', className)} style={containerStyle}>\n      <div style={contentStyle}>\n        {title && (\n          <h2 style={{ \n            fontSize: 'clamp(1.5rem, 4vw, 2.5rem)',\n            fontWeight: 700,\n            marginBottom: '0.5rem',\n          }}>\n            {title}\n          </h2>\n        )}\n\n        {subtitle && (\n          <p style={{ \n            fontSize: '1.2rem',\n            opacity: 0.9,\n            marginBottom: '2rem',\n          }}>\n            {subtitle}\n          </p>\n        )}\n\n        {button && (\n          <Button\n            text={button.text}\n            link={button.link}\n            variant={button.style || button.variant || 'secondary'}\n          />\n        )}\n      </div>\n    </section>\n  );\n};\n\nexport default CTABanner;\n\n","import React, { useState } from 'react';\nimport clsx from 'clsx';\nimport { ChevronDown } from 'lucide-react';\n\n/**\n * FAQ Accordion Section Component\n */\nconst FAQAccordion = ({\n  title,\n  subtitle,\n  items = [],\n  allowMultipleOpen = false,\n  backgroundColor = '#ffffff',\n  className = '',\n}) => {\n  const [openItems, setOpenItems] = useState(new Set());\n\n  const toggleItem = (index) => {\n    setOpenItems(prev => {\n      const newSet = new Set(allowMultipleOpen ? prev : []);\n      if (prev.has(index)) {\n        newSet.delete(index);\n      } else {\n        newSet.add(index);\n      }\n      return newSet;\n    });\n  };\n\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  return (\n    <section className={clsx('faq-accordion-section', className)} style={containerStyle}>\n      {(title || subtitle) && (\n        <div className=\"section-header\" style={{ textAlign: 'center', marginBottom: '3rem', maxWidth: '800px', margin: '0 auto 3rem' }}>\n          {title && <h2 style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{title}</h2>}\n          {subtitle && <p style={{ fontSize: '1.2rem', opacity: 0.8 }}>{subtitle}</p>}\n        </div>\n      )}\n\n      <div className=\"faq-list\" style={{ maxWidth: '800px', margin: '0 auto' }}>\n        {items.map((item, index) => (\n          <FAQItem\n            key={item.id || index}\n            question={item.question}\n            answer={item.answer}\n            isOpen={openItems.has(index)}\n            onToggle={() => toggleItem(index)}\n          />\n        ))}\n      </div>\n    </section>\n  );\n};\n\n/**\n * FAQ Item Component\n */\nconst FAQItem = ({ question, answer, isOpen, onToggle }) => {\n  return (\n    <div \n      className=\"faq-item\"\n      style={{\n        borderBottom: '1px solid #e5e7eb',\n        marginBottom: '0.5rem',\n      }}\n    >\n      <button\n        onClick={onToggle}\n        style={{\n          width: '100%',\n          display: 'flex',\n          justifyContent: 'space-between',\n          alignItems: 'center',\n          padding: '1.5rem 0',\n          background: 'none',\n          border: 'none',\n          cursor: 'pointer',\n          textAlign: 'left',\n          fontSize: '1.1rem',\n          fontWeight: 600,\n          color: '#1f2937',\n        }}\n      >\n        <span>{question}</span>\n        <ChevronDown \n          size={20}\n          style={{\n            transition: 'transform 0.2s',\n            transform: isOpen ? 'rotate(180deg)' : 'rotate(0deg)',\n            flexShrink: 0,\n            marginLeft: '1rem',\n          }}\n        />\n      </button>\n      \n      <div\n        style={{\n          overflow: 'hidden',\n          maxHeight: isOpen ? '1000px' : '0',\n          transition: 'max-height 0.3s ease-out',\n        }}\n      >\n        <div \n          style={{ \n            paddingBottom: '1.5rem',\n            color: '#4b5563',\n            lineHeight: 1.7,\n          }}\n          dangerouslySetInnerHTML={{ __html: answer }}\n        />\n      </div>\n    </div>\n  );\n};\n\nexport default FAQAccordion;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport * as Icons from 'lucide-react';\n\n/**\n * Feature Grid Section Component\n */\nconst FeatureGrid = ({\n  title,\n  subtitle,\n  columns = '3',\n  features = [],\n  backgroundColor = '#f8f9fa',\n  className = '',\n}) => {\n  const colCount = parseInt(columns, 10);\n\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  const gridStyle = {\n    display: 'grid',\n    gridTemplateColumns: `repeat(${colCount}, 1fr)`,\n    gap: '2rem',\n    maxWidth: '1200px',\n    margin: '0 auto',\n  };\n\n  return (\n    <section className={clsx('feature-grid-section', className)} style={containerStyle}>\n      {(title || subtitle) && (\n        <div className=\"section-header\" style={{ textAlign: 'center', marginBottom: '3rem' }}>\n          {title && <h2 style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{title}</h2>}\n          {subtitle && <p style={{ fontSize: '1.2rem', opacity: 0.8 }}>{subtitle}</p>}\n        </div>\n      )}\n\n      <div className=\"feature-grid\" style={gridStyle}>\n        {features.map((feature, index) => (\n          <FeatureCard key={feature.id || index} {...feature} />\n        ))}\n      </div>\n    </section>\n  );\n};\n\n/**\n * Feature Card Component\n */\nconst FeatureCard = ({\n  title,\n  description,\n  icon,\n  image,\n  link,\n  linkText = 'Learn more',\n}) => {\n  const imageUrl = image?.data?.attributes?.url || image?.url;\n  const IconComponent = icon && Icons[icon];\n\n  const cardStyle = {\n    background: '#ffffff',\n    borderRadius: '12px',\n    padding: '2rem',\n    boxShadow: '0 4px 6px rgba(0,0,0,0.05)',\n    transition: 'transform 0.2s, box-shadow 0.2s',\n    cursor: link ? 'pointer' : 'default',\n  };\n\n  const handleClick = () => {\n    if (link) {\n      window.location.href = link;\n    }\n  };\n\n  return (\n    <div \n      className=\"feature-card\" \n      style={cardStyle}\n      onClick={handleClick}\n      onMouseEnter={(e) => {\n        e.currentTarget.style.transform = 'translateY(-4px)';\n        e.currentTarget.style.boxShadow = '0 8px 25px rgba(0,0,0,0.1)';\n      }}\n      onMouseLeave={(e) => {\n        e.currentTarget.style.transform = 'translateY(0)';\n        e.currentTarget.style.boxShadow = '0 4px 6px rgba(0,0,0,0.05)';\n      }}\n    >\n      {imageUrl && (\n        <img \n          src={imageUrl} \n          alt={title}\n          style={{ \n            width: '100%', \n            height: '150px', \n            objectFit: 'cover',\n            borderRadius: '8px',\n            marginBottom: '1rem',\n          }}\n        />\n      )}\n\n      {IconComponent && !imageUrl && (\n        <div style={{ \n          width: '60px', \n          height: '60px', \n          borderRadius: '12px',\n          background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)',\n          display: 'flex',\n          alignItems: 'center',\n          justifyContent: 'center',\n          marginBottom: '1rem',\n        }}>\n          <IconComponent size={28} color=\"#fff\" />\n        </div>\n      )}\n\n      {title && (\n        <h3 style={{ fontSize: '1.25rem', marginBottom: '0.5rem', fontWeight: 600 }}>\n          {title}\n        </h3>\n      )}\n\n      {description && (\n        <p style={{ color: '#666', lineHeight: 1.6, marginBottom: link ? '1rem' : 0 }}>\n          {description}\n        </p>\n      )}\n\n      {link && (\n        <a \n          href={link}\n          style={{ \n            color: '#4f46e5', \n            textDecoration: 'none',\n            fontWeight: 500,\n            display: 'inline-flex',\n            alignItems: 'center',\n            gap: '0.5rem',\n          }}\n          onClick={(e) => e.stopPropagation()}\n        >\n          {linkText} →\n        </a>\n      )}\n    </div>\n  );\n};\n\nexport default FeatureGrid;\n\n","import React, { useState } from 'react';\nimport clsx from 'clsx';\nimport { X, ChevronLeft, ChevronRight } from 'lucide-react';\n\n/**\n * Image Gallery Section Component\n */\nconst ImageGallery = ({\n  title,\n  images = [],\n  columns = '3',\n  enableLightbox = true,\n  aspectRatio = 'square',\n  className = '',\n}) => {\n  const [lightboxOpen, setLightboxOpen] = useState(false);\n  const [currentIndex, setCurrentIndex] = useState(0);\n\n  const colCount = parseInt(columns, 10);\n  \n  const aspectRatioMap = {\n    square: '1 / 1',\n    portrait: '3 / 4',\n    landscape: '16 / 9',\n    auto: 'auto',\n  };\n\n  // Handle both array of media objects and direct URLs\n  const imageList = images?.data?.map(img => ({\n    url: img.attributes?.url || img.url,\n    alt: img.attributes?.alternativeText || img.alternativeText || '',\n  })) || images.map?.(img => ({\n    url: img.url || img,\n    alt: img.alt || '',\n  })) || [];\n\n  const openLightbox = (index) => {\n    if (enableLightbox) {\n      setCurrentIndex(index);\n      setLightboxOpen(true);\n    }\n  };\n\n  const closeLightbox = () => setLightboxOpen(false);\n  const nextImage = () => setCurrentIndex((prev) => (prev + 1) % imageList.length);\n  const prevImage = () => setCurrentIndex((prev) => (prev - 1 + imageList.length) % imageList.length);\n\n  return (\n    <section className={clsx('image-gallery-section', className)} style={{ padding: '4rem 2rem' }}>\n      {title && (\n        <h2 style={{ \n          textAlign: 'center', \n          fontSize: '2.5rem', \n          marginBottom: '2rem',\n        }}>\n          {title}\n        </h2>\n      )}\n\n      <div \n        className=\"gallery-grid\"\n        style={{\n          display: 'grid',\n          gridTemplateColumns: `repeat(${colCount}, 1fr)`,\n          gap: '1rem',\n          maxWidth: '1200px',\n          margin: '0 auto',\n        }}\n      >\n        {imageList.map((image, index) => (\n          <div\n            key={index}\n            onClick={() => openLightbox(index)}\n            style={{\n              aspectRatio: aspectRatioMap[aspectRatio],\n              overflow: 'hidden',\n              borderRadius: '8px',\n              cursor: enableLightbox ? 'pointer' : 'default',\n              transition: 'transform 0.2s',\n            }}\n            onMouseEnter={(e) => {\n              if (enableLightbox) e.currentTarget.style.transform = 'scale(1.02)';\n            }}\n            onMouseLeave={(e) => {\n              e.currentTarget.style.transform = 'scale(1)';\n            }}\n          >\n            <img\n              src={image.url}\n              alt={image.alt}\n              style={{\n                width: '100%',\n                height: '100%',\n                objectFit: 'cover',\n              }}\n            />\n          </div>\n        ))}\n      </div>\n\n      {/* Lightbox */}\n      {lightboxOpen && (\n        <div\n          style={{\n            position: 'fixed',\n            top: 0,\n            left: 0,\n            right: 0,\n            bottom: 0,\n            background: 'rgba(0,0,0,0.95)',\n            zIndex: 9999,\n            display: 'flex',\n            alignItems: 'center',\n            justifyContent: 'center',\n          }}\n          onClick={closeLightbox}\n        >\n          <button\n            onClick={closeLightbox}\n            style={{\n              position: 'absolute',\n              top: '1rem',\n              right: '1rem',\n              background: 'transparent',\n              border: 'none',\n              color: '#fff',\n              cursor: 'pointer',\n              padding: '0.5rem',\n            }}\n          >\n            <X size={32} />\n          </button>\n\n          {imageList.length > 1 && (\n            <>\n              <button\n                onClick={(e) => { e.stopPropagation(); prevImage(); }}\n                style={{\n                  position: 'absolute',\n                  left: '1rem',\n                  background: 'transparent',\n                  border: 'none',\n                  color: '#fff',\n                  cursor: 'pointer',\n                  padding: '1rem',\n                }}\n              >\n                <ChevronLeft size={40} />\n              </button>\n              <button\n                onClick={(e) => { e.stopPropagation(); nextImage(); }}\n                style={{\n                  position: 'absolute',\n                  right: '1rem',\n                  background: 'transparent',\n                  border: 'none',\n                  color: '#fff',\n                  cursor: 'pointer',\n                  padding: '1rem',\n                }}\n              >\n                <ChevronRight size={40} />\n              </button>\n            </>\n          )}\n\n          <img\n            src={imageList[currentIndex]?.url}\n            alt={imageList[currentIndex]?.alt}\n            onClick={(e) => e.stopPropagation()}\n            style={{\n              maxWidth: '90vw',\n              maxHeight: '90vh',\n              objectFit: 'contain',\n            }}\n          />\n        </div>\n      )}\n    </section>\n  );\n};\n\nexport default ImageGallery;\n\n","import React, { useState } from 'react';\nimport clsx from 'clsx';\nimport { Check, X } from 'lucide-react';\nimport Button from '../forms/Button';\n\n/**\n * Pricing Table Section Component\n */\nconst PricingTable = ({\n  title,\n  subtitle,\n  plans = [],\n  showToggle = true,\n  monthlyLabel = 'Monthly',\n  yearlyLabel = 'Yearly',\n  backgroundColor = '#ffffff',\n  className = '',\n}) => {\n  const [billingPeriod, setBillingPeriod] = useState('monthly');\n\n  // Auto-detect if toggle is useful: only show if plans use monthlyPrice/yearlyPrice\n  const hasLegacyPricing = plans.some(p => p.monthlyPrice != null || p.yearlyPrice != null);\n  const shouldShowToggle = showToggle && hasLegacyPricing;\n\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  return (\n    <section className={clsx('pricing-table-section', className)} style={containerStyle}>\n      {(title || subtitle) && (\n        <div className=\"section-header\" style={{ textAlign: 'center', marginBottom: '2rem' }}>\n          {title && <h2 style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{title}</h2>}\n          {subtitle && <p style={{ fontSize: '1.2rem', opacity: 0.8 }}>{subtitle}</p>}\n        </div>\n      )}\n\n      {shouldShowToggle && (\n        <div style={{ \n          display: 'flex', \n          justifyContent: 'center', \n          alignItems: 'center',\n          gap: '1rem',\n          marginBottom: '3rem',\n        }}>\n          <span style={{ \n            fontWeight: billingPeriod === 'monthly' ? 600 : 400,\n            color: billingPeriod === 'monthly' ? '#1f2937' : '#9ca3af',\n          }}>\n            {monthlyLabel}\n          </span>\n          \n          <button\n            onClick={() => setBillingPeriod(p => p === 'monthly' ? 'yearly' : 'monthly')}\n            style={{\n              width: '56px',\n              height: '28px',\n              borderRadius: '14px',\n              background: '#4f46e5',\n              border: 'none',\n              cursor: 'pointer',\n              position: 'relative',\n              padding: 0,\n            }}\n          >\n            <span style={{\n              position: 'absolute',\n              top: '2px',\n              left: billingPeriod === 'yearly' ? '30px' : '2px',\n              width: '24px',\n              height: '24px',\n              borderRadius: '50%',\n              background: '#fff',\n              transition: 'left 0.2s',\n            }} />\n          </button>\n          \n          <span style={{ \n            fontWeight: billingPeriod === 'yearly' ? 600 : 400,\n            color: billingPeriod === 'yearly' ? '#1f2937' : '#9ca3af',\n          }}>\n            {yearlyLabel}\n          </span>\n        </div>\n      )}\n\n      <div \n        className=\"pricing-grid\"\n        style={{\n          display: 'grid',\n          gridTemplateColumns: `repeat(${Math.min(plans.length, 4)}, 1fr)`,\n          gap: '2rem',\n          maxWidth: '1200px',\n          margin: '0 auto',\n          alignItems: 'stretch',\n        }}\n      >\n        {plans.map((plan, index) => (\n          <PricingCard \n            key={plan.id || index} \n            {...plan} \n            billingPeriod={billingPeriod}\n          />\n        ))}\n      </div>\n    </section>\n  );\n};\n\n/**\n * Pricing Card Component\n * Supports both legacy props (monthlyPrice, yearlyPrice, ctaButton, features as [{text,included}])\n * and Strapi props (price, period, cta, isPopular, features as string[])\n */\nconst PricingCard = ({\n  name,\n  description,\n  monthlyPrice,\n  yearlyPrice,\n  price: strapiPrice,\n  period: strapiPeriod,\n  currency = '$',\n  billingPeriod,\n  features = [],\n  ctaButton,\n  cta,\n  highlighted = false,\n  isPopular,\n  badge,\n}) => {\n  // Resolve highlighted from either prop\n  const isHighlighted = highlighted || isPopular || false;\n\n  // Resolve price: prefer Strapi's flat `price` string, fallback to legacy monthly/yearly\n  let displayPrice;\n  let displayPeriod;\n\n  if (strapiPrice !== undefined) {\n    // Strapi format: price is a string like \"Free\", \"$49\", \"Custom\"\n    displayPrice = strapiPrice;\n    displayPeriod = strapiPeriod || '';\n  } else {\n    // Legacy format: monthlyPrice / yearlyPrice are numbers\n    const numPrice = billingPeriod === 'yearly' && yearlyPrice ? yearlyPrice : monthlyPrice;\n    displayPrice = numPrice != null ? `${currency}${numPrice}` : '';\n    displayPeriod = billingPeriod === 'yearly' ? '/year' : '/month';\n  }\n\n  // Resolve CTA button: Strapi sends `cta`, legacy sends `ctaButton`\n  const resolvedCta = cta || ctaButton;\n\n  // Resolve badge for popular plans\n  const resolvedBadge = badge || (isPopular ? 'Most Popular' : null);\n\n  // Normalize features: handle both string[] and [{text, included}]\n  const normalizedFeatures = features.map((f) => {\n    if (typeof f === 'string') {\n      return { text: f, included: true };\n    }\n    return f;\n  });\n\n  const cardStyle = {\n    background: isHighlighted ? 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)' : '#fff',\n    color: isHighlighted ? '#fff' : '#1f2937',\n    borderRadius: '16px',\n    padding: '2rem',\n    boxShadow: isHighlighted\n      ? '0 20px 40px rgba(79, 70, 229, 0.3)'\n      : '0 4px 20px rgba(0,0,0,0.08)',\n    position: 'relative',\n    transform: isHighlighted ? 'scale(1.05)' : 'scale(1)',\n    display: 'flex',\n    flexDirection: 'column',\n  };\n\n  return (\n    <div className=\"pricing-card\" style={cardStyle}>\n      {resolvedBadge && (\n        <div style={{\n          position: 'absolute',\n          top: '-12px',\n          left: '50%',\n          transform: 'translateX(-50%)',\n          background: isHighlighted ? '#fff' : '#4f46e5',\n          color: isHighlighted ? '#4f46e5' : '#fff',\n          padding: '0.25rem 1rem',\n          borderRadius: '20px',\n          fontSize: '0.875rem',\n          fontWeight: 600,\n        }}>\n          {resolvedBadge}\n        </div>\n      )}\n\n      <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>\n        <h3 style={{ fontSize: '1.5rem', fontWeight: 600, marginBottom: '0.5rem' }}>{name}</h3>\n        {description && (\n          <p style={{ opacity: 0.8, fontSize: '0.9rem' }}>{description}</p>\n        )}\n      </div>\n\n      <div style={{ textAlign: 'center', marginBottom: '2rem' }}>\n        <span style={{ fontSize: '3rem', fontWeight: 700 }}>\n          {displayPrice}\n        </span>\n        {displayPeriod && <span style={{ opacity: 0.8 }}>{displayPeriod}</span>}\n      </div>\n\n      <ul style={{\n        listStyle: 'none',\n        padding: 0,\n        margin: 0,\n        marginBottom: '2rem',\n        flex: 1,\n      }}>\n        {normalizedFeatures.map((feature, idx) => (\n          <li\n            key={idx}\n            style={{\n              display: 'flex',\n              alignItems: 'center',\n              gap: '0.75rem',\n              padding: '0.5rem 0',\n              opacity: feature.included !== false ? 1 : 0.5,\n            }}\n          >\n            {feature.included !== false ? (\n              <Check size={18} color={isHighlighted ? '#fff' : '#22c55e'} />\n            ) : (\n              <X size={18} color={isHighlighted ? 'rgba(255,255,255,0.5)' : '#ef4444'} />\n            )}\n            <span>{feature.text}</span>\n          </li>\n        ))}\n      </ul>\n\n      {resolvedCta && (\n        <Button\n          text={resolvedCta.text || resolvedCta.label}\n          link={resolvedCta.link || resolvedCta.href || resolvedCta.url}\n          variant={isHighlighted ? 'secondary' : (resolvedCta.style || resolvedCta.variant || 'primary')}\n          size=\"large\"\n          style={{\n            width: '100%',\n            background: isHighlighted ? '#fff' : undefined,\n            color: isHighlighted ? '#4f46e5' : undefined,\n          }}\n        />\n      )}\n    </div>\n  );\n};\n\nexport default PricingTable;\n\n","import React, { useState, useEffect, useRef } from 'react';\nimport clsx from 'clsx';\nimport * as Icons from 'lucide-react';\n\n/**\n * Stats Counter Section Component\n */\nconst StatsCounter = ({\n  title,\n  subtitle,\n  stats = [],\n  backgroundColor = '#4f46e5',\n  gradientFrom,\n  gradientTo,\n  textColor = '#ffffff',\n  animateOnScroll = true,\n  className = '',\n}) => {\n  const [isVisible, setIsVisible] = useState(!animateOnScroll);\n  const sectionRef = useRef(null);\n\n  useEffect(() => {\n    if (!animateOnScroll) return;\n\n    const observer = new IntersectionObserver(\n      ([entry]) => {\n        if (entry.isIntersecting) {\n          setIsVisible(true);\n          observer.disconnect();\n        }\n      },\n      { threshold: 0.2 }\n    );\n\n    if (sectionRef.current) {\n      observer.observe(sectionRef.current);\n    }\n\n    return () => observer.disconnect();\n  }, [animateOnScroll]);\n\n  const containerStyle = {\n    ...(gradientFrom && gradientTo\n      ? { backgroundImage: `linear-gradient(135deg, ${gradientFrom}, ${gradientTo})` }\n      : { backgroundColor }),\n    color: textColor,\n    padding: '4rem 2rem',\n  };\n\n  return (\n    <section \n      ref={sectionRef}\n      className={clsx('stats-counter-section', className)} \n      style={containerStyle}\n    >\n      {(title || subtitle) && (\n        <div className=\"section-header\" style={{ textAlign: 'center', marginBottom: '3rem' }}>\n          {title && <h2 style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{title}</h2>}\n          {subtitle && <p style={{ fontSize: '1.2rem', opacity: 0.9 }}>{subtitle}</p>}\n        </div>\n      )}\n\n      <div \n        className=\"stats-grid\"\n        style={{\n          display: 'grid',\n          gridTemplateColumns: `repeat(${Math.min(stats.length, 4)}, 1fr)`,\n          gap: '2rem',\n          maxWidth: '1200px',\n          margin: '0 auto',\n          textAlign: 'center',\n        }}\n      >\n        {stats.map((stat, index) => (\n          <StatItem \n            key={stat.id || index} \n            {...stat} \n            isVisible={isVisible}\n            delay={index * 100}\n          />\n        ))}\n      </div>\n    </section>\n  );\n};\n\n/**\n * Stat Item Component with counter animation\n */\nconst StatItem = ({\n  value,\n  label,\n  prefix = '',\n  suffix = '',\n  icon,\n  isVisible,\n  delay = 0,\n}) => {\n  const [displayValue, setDisplayValue] = useState('0');\n  const IconComponent = icon && Icons[icon];\n  \n  // Parse numeric value for animation\n  const numericValue = parseFloat(value?.replace(/[^0-9.]/g, '')) || 0;\n  const isNumeric = !isNaN(numericValue) && numericValue > 0;\n\n  useEffect(() => {\n    if (!isVisible || !isNumeric) {\n      setDisplayValue(value);\n      return;\n    }\n\n    const duration = 2000;\n    const steps = 60;\n    const stepDuration = duration / steps;\n    const increment = numericValue / steps;\n    \n    let current = 0;\n    \n    const timer = setTimeout(() => {\n      const interval = setInterval(() => {\n        current += increment;\n        if (current >= numericValue) {\n          setDisplayValue(value);\n          clearInterval(interval);\n        } else {\n          setDisplayValue(Math.floor(current).toLocaleString());\n        }\n      }, stepDuration);\n\n      return () => clearInterval(interval);\n    }, delay);\n\n    return () => clearTimeout(timer);\n  }, [isVisible, value, numericValue, isNumeric, delay]);\n\n  return (\n    <div className=\"stat-item\">\n      {IconComponent && (\n        <div style={{ marginBottom: '1rem' }}>\n          <IconComponent size={40} strokeWidth={1.5} />\n        </div>\n      )}\n      \n      <div style={{ \n        fontSize: 'clamp(2rem, 5vw, 3.5rem)',\n        fontWeight: 700,\n        marginBottom: '0.5rem',\n      }}>\n        {prefix}{displayValue}{suffix}\n      </div>\n      \n      <div style={{ \n        fontSize: '1rem',\n        opacity: 0.9,\n        textTransform: 'uppercase',\n        letterSpacing: '0.05em',\n      }}>\n        {label}\n      </div>\n    </div>\n  );\n};\n\nexport default StatsCounter;\n\n","export function deprecate(fn) {\n  return fn\n}\n\nexport function equal() {}\n\nexport function ok() {}\n\nexport function unreachable() {}\n","/**\n * @typedef Options\n *   Configuration for `stringify`.\n * @property {boolean} [padLeft=true]\n *   Whether to pad a space before a token.\n * @property {boolean} [padRight=false]\n *   Whether to pad a space after a token.\n */\n\n/**\n * @typedef {Options} StringifyOptions\n *   Please use `StringifyOptions` instead.\n */\n\n/**\n * Parse comma-separated tokens to an array.\n *\n * @param {string} value\n *   Comma-separated tokens.\n * @returns {Array<string>}\n *   List of tokens.\n */\nexport function parse(value) {\n  /** @type {Array<string>} */\n  const tokens = []\n  const input = String(value || '')\n  let index = input.indexOf(',')\n  let start = 0\n  /** @type {boolean} */\n  let end = false\n\n  while (!end) {\n    if (index === -1) {\n      index = input.length\n      end = true\n    }\n\n    const token = input.slice(start, index).trim()\n\n    if (token || !end) {\n      tokens.push(token)\n    }\n\n    start = index + 1\n    index = input.indexOf(',', start)\n  }\n\n  return tokens\n}\n\n/**\n * Serialize an array of strings or numbers to comma-separated tokens.\n *\n * @param {Array<string|number>} values\n *   List of tokens.\n * @param {Options} [options]\n *   Configuration for `stringify` (optional).\n * @returns {string}\n *   Comma-separated tokens.\n */\nexport function stringify(values, options) {\n  const settings = options || {}\n\n  // Ensure the last empty entry is seen.\n  const input = values[values.length - 1] === '' ? [...values, ''] : values\n\n  return input\n    .join(\n      (settings.padRight ? ' ' : '') +\n        ',' +\n        (settings.padLeft === false ? '' : ' ')\n    )\n    .trim()\n}\n","/**\n * @typedef Options\n *   Configuration.\n * @property {boolean | null | undefined} [jsx=false]\n *   Support JSX identifiers (default: `false`).\n */\n\nconst startRe = /[$_\\p{ID_Start}]/u\nconst contRe = /[$_\\u{200C}\\u{200D}\\p{ID_Continue}]/u\nconst contReJsx = /[-$_\\u{200C}\\u{200D}\\p{ID_Continue}]/u\nconst nameRe = /^[$_\\p{ID_Start}][$_\\u{200C}\\u{200D}\\p{ID_Continue}]*$/u\nconst nameReJsx = /^[$_\\p{ID_Start}][-$_\\u{200C}\\u{200D}\\p{ID_Continue}]*$/u\n\n/** @type {Options} */\nconst emptyOptions = {}\n\n/**\n * Checks if the given code point can start an identifier.\n *\n * @param {number | undefined} code\n *   Code point to check.\n * @returns {boolean}\n *   Whether `code` can start an identifier.\n */\n// Note: `undefined` is supported so you can pass the result from `''.codePointAt`.\nexport function start(code) {\n  return code ? startRe.test(String.fromCodePoint(code)) : false\n}\n\n/**\n * Checks if the given code point can continue an identifier.\n *\n * @param {number | undefined} code\n *   Code point to check.\n * @param {Options | null | undefined} [options]\n *   Configuration (optional).\n * @returns {boolean}\n *   Whether `code` can continue an identifier.\n */\n// Note: `undefined` is supported so you can pass the result from `''.codePointAt`.\nexport function cont(code, options) {\n  const settings = options || emptyOptions\n  const re = settings.jsx ? contReJsx : contRe\n  return code ? re.test(String.fromCodePoint(code)) : false\n}\n\n/**\n * Checks if the given value is a valid identifier name.\n *\n * @param {string} name\n *   Identifier to check.\n * @param {Options | null | undefined} [options]\n *   Configuration (optional).\n * @returns {boolean}\n *   Whether `name` can be an identifier.\n */\nexport function name(name, options) {\n  const settings = options || emptyOptions\n  const re = settings.jsx ? nameReJsx : nameRe\n  return re.test(name)\n}\n","/**\n * @typedef {import('hast').Nodes} Nodes\n */\n\n// HTML whitespace expression.\n// See <https://infra.spec.whatwg.org/#ascii-whitespace>.\nconst re = /[ \\t\\n\\f\\r]/g\n\n/**\n * Check if the given value is *inter-element whitespace*.\n *\n * @param {Nodes | string} thing\n *   Thing to check (`Node` or `string`).\n * @returns {boolean}\n *   Whether the `value` is inter-element whitespace (`boolean`): consisting of\n *   zero or more of space, tab (`\\t`), line feed (`\\n`), carriage return\n *   (`\\r`), or form feed (`\\f`); if a node is passed it must be a `Text` node,\n *   whose `value` field is checked.\n */\nexport function whitespace(thing) {\n  return typeof thing === 'object'\n    ? thing.type === 'text'\n      ? empty(thing.value)\n      : false\n    : empty(thing)\n}\n\n/**\n * @param {string} value\n * @returns {boolean}\n */\nfunction empty(value) {\n  return value.replace(re, '') === ''\n}\n","/**\n * @import {Schema as SchemaType, Space} from 'property-information'\n */\n\n/** @type {SchemaType} */\nexport class Schema {\n  /**\n   * @param {SchemaType['property']} property\n   *   Property.\n   * @param {SchemaType['normal']} normal\n   *   Normal.\n   * @param {Space | undefined} [space]\n   *   Space.\n   * @returns\n   *   Schema.\n   */\n  constructor(property, normal, space) {\n    this.normal = normal\n    this.property = property\n\n    if (space) {\n      this.space = space\n    }\n  }\n}\n\nSchema.prototype.normal = {}\nSchema.prototype.property = {}\nSchema.prototype.space = undefined\n","/**\n * @import {Info, Space} from 'property-information'\n */\n\nimport {Schema} from './schema.js'\n\n/**\n * @param {ReadonlyArray<Schema>} definitions\n *   Definitions.\n * @param {Space | undefined} [space]\n *   Space.\n * @returns {Schema}\n *   Schema.\n */\nexport function merge(definitions, space) {\n  /** @type {Record<string, Info>} */\n  const property = {}\n  /** @type {Record<string, string>} */\n  const normal = {}\n\n  for (const definition of definitions) {\n    Object.assign(property, definition.property)\n    Object.assign(normal, definition.normal)\n  }\n\n  return new Schema(property, normal, space)\n}\n","/**\n * Get the cleaned case insensitive form of an attribute or property.\n *\n * @param {string} value\n *   An attribute-like or property-like name.\n * @returns {string}\n *   Value that can be used to look up the properly cased property on a\n *   `Schema`.\n */\nexport function normalize(value) {\n  return value.toLowerCase()\n}\n","/**\n * @import {Info as InfoType} from 'property-information'\n */\n\n/** @type {InfoType} */\nexport class Info {\n  /**\n   * @param {string} property\n   *   Property.\n   * @param {string} attribute\n   *   Attribute.\n   * @returns\n   *   Info.\n   */\n  constructor(property, attribute) {\n    this.attribute = attribute\n    this.property = property\n  }\n}\n\nInfo.prototype.attribute = ''\nInfo.prototype.booleanish = false\nInfo.prototype.boolean = false\nInfo.prototype.commaOrSpaceSeparated = false\nInfo.prototype.commaSeparated = false\nInfo.prototype.defined = false\nInfo.prototype.mustUseProperty = false\nInfo.prototype.number = false\nInfo.prototype.overloadedBoolean = false\nInfo.prototype.property = ''\nInfo.prototype.spaceSeparated = false\nInfo.prototype.space = undefined\n","let powers = 0\n\nexport const boolean = increment()\nexport const booleanish = increment()\nexport const overloadedBoolean = increment()\nexport const number = increment()\nexport const spaceSe