uld do it.\n  state.parser.tokenizer.lastStartTagName = tagName\n\n  // `inForeignNode` is correctly set by the parser.\n}\n\n/**\n * Emit an end tag.\n *\n * @param {Element} node\n *   Element.\n * @param {State} state\n *   Info passed around about the current state.\n * @returns {undefined}\n *   Nothing.\n */\nfunction endTag(node, state) {\n  const tagName = node.tagName.toLowerCase()\n  // Do not emit closing tags for HTML void elements.\n  if (\n    !state.parser.tokenizer.inForeignNode &&\n    htmlVoidElements.includes(tagName)\n  ) {\n    return\n  }\n\n  // Ignore tags if we’re in plain text.\n  if (state.parser.tokenizer.state === TokenizerMode.PLAINTEXT) return\n\n  resetTokenizer(state, pointEnd(node))\n\n  /** @type {Token.TagToken} */\n  const tag = {\n    type: Token.TokenType.END_TAG,\n    tagName,\n    tagID: html.getTagID(tagName),\n    selfClosing: false,\n    ackSelfClosing: false,\n    attrs: [],\n    location: createParse5Location(node)\n  }\n\n  // The HTML parsing algorithm works by doing half of the state management in\n  // the tokenizer and half in the parser.\n  // We can’t use the tokenizer here, as we don’t have strings.\n  // So we act *as if* the tokenizer emits tokens:\n\n  // @ts-expect-error: private.\n  state.parser.currentToken = tag\n  // @ts-expect-error: private.\n  state.parser._processToken(state.parser.currentToken)\n\n  // …but then we still need a bunch of work that the tokenizer would normally\n  // do, such as:\n\n  // Switch back to the data state after alternative states that don’t accept\n  // tags:\n  if (\n    // Current element is closed.\n    tagName === state.parser.tokenizer.lastStartTagName &&\n    // `<textarea>` and `<title>`\n    (state.parser.tokenizer.state === TokenizerMode.RCDATA ||\n      // `<iframe>`, `<noembed>`, `<noframes>`, `<style>`, `<xmp>`\n      state.parser.tokenizer.state === TokenizerMode.RAWTEXT ||\n      // `<script>`\n      state.parser.tokenizer.state === TokenizerMode.SCRIPT_DATA)\n    // Note: `<plaintext>` not needed, as it’s the last element.\n  ) {\n    state.parser.tokenizer.state = TokenizerMode.DATA\n  }\n}\n\n/**\n * Check if `node` represents a whole document or a fragment.\n *\n * @param {Nodes} node\n *   hast node.\n * @returns {boolean}\n *   Whether this represents a whole document or a fragment.\n */\nfunction documentMode(node) {\n  const head = node.type === 'root' ? node.children[0] : node\n  return Boolean(\n    head &&\n      (head.type === 'doctype' ||\n        (head.type === 'element' && head.tagName.toLowerCase() === 'html'))\n  )\n}\n\n/**\n * Get a `parse5` location from a node.\n *\n * @param {Nodes | Stitch} node\n *   hast node.\n * @returns {Token.Location}\n *   `parse5` location.\n */\nfunction createParse5Location(node) {\n  const start = pointStart(node) || {\n    line: undefined,\n    column: undefined,\n    offset: undefined\n  }\n  const end = pointEnd(node) || {\n    line: undefined,\n    column: undefined,\n    offset: undefined\n  }\n\n  /** @type {Record<keyof Token.Location, number | undefined>} */\n  const location = {\n    startLine: start.line,\n    startCol: start.column,\n    startOffset: start.offset,\n    endLine: end.line,\n    endCol: end.column,\n    endOffset: end.offset\n  }\n\n  // @ts-expect-error: unist point values can be `undefined` in hast, which\n  // `parse5` types don’t want.\n  return location\n}\n\n/**\n * @template {Nodes} NodeType\n *   Node type.\n * @param {NodeType} node\n *   Node to clone.\n * @returns {NodeType}\n *   Cloned node, without children.\n */\nfunction cloneWithoutChildren(node) {\n  return 'children' in node\n    ? structuredClone({...node, children: []})\n    : structuredClone(node)\n}\n","/**\n * @typedef {import('hast').Root} Root\n * @typedef {import('hast-util-raw').Options} RawOptions\n * @typedef {import('vfile').VFile} VFile\n */\n\n/**\n * @typedef {Omit<RawOptions, 'file'>} Options\n *   Configuration.\n */\n\nimport {raw} from 'hast-util-raw'\n\n/**\n * Parse the tree (and raw nodes) again, keeping positional info okay.\n *\n * @param {Options | null | undefined}  [options]\n *   Configuration (optional).\n * @returns\n *   Transform.\n */\nexport default function rehypeRaw(options) {\n  /**\n   * @param {Root} tree\n   *   Tree.\n   * @param {VFile} file\n   *   File.\n   * @returns {Root}\n   *   New tree.\n   */\n  return function (tree, file) {\n    // Assume root in -> root out.\n    const result = /** @type {Root} */ (raw(tree, {...options, file}))\n    return result\n  }\n}\n","import React, { useState } from 'react';\nimport clsx from 'clsx';\nimport * as Icons from 'lucide-react';\nimport ReactMarkdown from 'react-markdown';\nimport rehypeRaw from 'rehype-raw';\n\n/**\n * Tabs Section Component\n */\nconst TabsSection = ({\n  title,\n  tabs = [],\n  tabStyle = 'underline',\n  defaultTab = 0,\n  backgroundColor = '#ffffff',\n  className = '',\n}) => {\n  const [activeTab, setActiveTab] = useState(defaultTab);\n\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  const getTabStyle = (index) => {\n    const isActive = index === activeTab;\n    const baseStyle = {\n      padding: '0.75rem 1.5rem',\n      border: 'none',\n      background: 'none',\n      cursor: 'pointer',\n      fontSize: '1rem',\n      fontWeight: isActive ? 600 : 400,\n      color: isActive ? '#4f46e5' : '#6b7280',\n      display: 'flex',\n      alignItems: 'center',\n      gap: '0.5rem',\n      transition: 'all 0.2s',\n    };\n\n    switch (tabStyle) {\n      case 'pills':\n        return {\n          ...baseStyle,\n          borderRadius: '9999px',\n          background: isActive ? '#4f46e5' : 'transparent',\n          color: isActive ? '#fff' : '#6b7280',\n        };\n      case 'boxed':\n        return {\n          ...baseStyle,\n          borderRadius: '8px 8px 0 0',\n          background: isActive ? '#fff' : '#f3f4f6',\n          borderBottom: isActive ? '2px solid #fff' : '2px solid transparent',\n          marginBottom: '-2px',\n        };\n      case 'underline':\n      default:\n        return {\n          ...baseStyle,\n          borderBottom: isActive ? '2px solid #4f46e5' : '2px solid transparent',\n        };\n    }\n  };\n\n  return (\n    <section className={clsx('tabs-section', className)} style={containerStyle}>\n      <div style={{ maxWidth: '900px', margin: '0 auto' }}>\n        {title && (\n          <h2 style={{ \n            textAlign: 'center', \n            fontSize: '2.5rem', \n            marginBottom: '2rem',\n          }}>\n            {title}\n          </h2>\n        )}\n\n        {/* Tab Headers */}\n        <div\n          className=\"tabs-header\"\n          style={{\n            display: 'flex',\n            justifyContent: 'center',\n            flexWrap: 'wrap',\n            gap: tabStyle === 'pills' ? '0.5rem' : '0',\n            borderBottom: tabStyle === 'underline' ? '1px solid #e5e7eb' :\n                          tabStyle === 'boxed' ? '2px solid #e5e7eb' : 'none',\n            marginBottom: '2rem',\n          }}\n        >\n          {tabs.map((tab, index) => {\n            const IconComponent = tab.icon && Icons[tab.icon];\n            return (\n              <button\n                key={index}\n                onClick={() => setActiveTab(index)}\n                style={getTabStyle(index)}\n              >\n                {IconComponent && <IconComponent size={18} />}\n                {tab.label}\n              </button>\n            );\n          })}\n        </div>\n\n        {/* Tab Content */}\n        <div className=\"tab-content\">\n          {tabs[activeTab] && (\n            <div\n              className=\"tab-content-body\"\n              style={{\n                lineHeight: 1.8,\n                color: '#374151',\n              }}\n            >\n              <ReactMarkdown rehypePlugins={[rehypeRaw]}>\n                {tabs[activeTab].content || ''}\n              </ReactMarkdown>\n            </div>\n          )}\n        </div>\n        <style>{`\n          .tab-content-body h2 { font-size: 1.75rem; font-weight: 700; margin: 1.5rem 0 1rem; color: #111827; }\n          .tab-content-body h3 { font-size: 1.25rem; font-weight: 600; margin: 1.25rem 0 0.75rem; color: #1f2937; }\n          .tab-content-body p { margin: 0.75rem 0; }\n          .tab-content-body ul, .tab-content-body ol { margin: 0.75rem 0; padding-left: 1.5rem; }\n          .tab-content-body li { margin: 0.25rem 0; }\n          .tab-content-body code { background: #f3f4f6; padding: 0.15rem 0.4rem; border-radius: 4px; font-size: 0.9em; color: #7c3aed; }\n          .tab-content-body pre { background: #1e293b; color: #e2e8f0; padding: 1rem 1.25rem; border-radius: 8px; overflow-x: auto; margin: 1rem 0; }\n          .tab-content-body pre code { background: none; color: inherit; padding: 0; }\n          .tab-content-body strong { font-weight: 600; color: #111827; }\n          .tab-content-body a { color: #7c3aed; text-decoration: underline; }\n        `}</style>\n      </div>\n    </section>\n  );\n};\n\nexport default TabsSection;\n\n","import React, { useState, useEffect } from 'react';\nimport clsx from 'clsx';\nimport { ChevronLeft, ChevronRight, Star } from 'lucide-react';\n\n/**\n * Testimonials Section Component\n */\nconst Testimonials = ({\n  title,\n  subtitle,\n  displayMode = 'carousel',\n  items = [],\n  backgroundColor = '#f8f9fa',\n  className = '',\n}) => {\n  const [currentIndex, setCurrentIndex] = useState(0);\n\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  // Auto-advance carousel\n  useEffect(() => {\n    if (displayMode === 'carousel' && items.length > 1) {\n      const timer = setInterval(() => {\n        setCurrentIndex(prev => (prev + 1) % items.length);\n      }, 5000);\n      return () => clearInterval(timer);\n    }\n  }, [displayMode, items.length]);\n\n  const nextSlide = () => setCurrentIndex(prev => (prev + 1) % items.length);\n  const prevSlide = () => setCurrentIndex(prev => (prev - 1 + items.length) % items.length);\n\n  return (\n    <section className={clsx('testimonials-section', className)} style={containerStyle}>\n      {(title || subtitle) && (\n        <div className=\"section-header\" style={{ textAlign: 'center', marginBottom: '3rem' }}>\n          {title && <h2 style={{ fontSize: '2.5rem', marginBottom: '0.5rem' }}>{title}</h2>}\n          {subtitle && <p style={{ fontSize: '1.2rem', opacity: 0.8 }}>{subtitle}</p>}\n        </div>\n      )}\n\n      {displayMode === 'carousel' ? (\n        <div className=\"testimonials-carousel\" style={{ \n          position: 'relative', \n          maxWidth: '800px', \n          margin: '0 auto',\n        }}>\n          <TestimonialCard {...items[currentIndex]} />\n          \n          {items.length > 1 && (\n            <>\n              <button\n                onClick={prevSlide}\n                style={{\n                  position: 'absolute',\n                  left: '-60px',\n                  top: '50%',\n                  transform: 'translateY(-50%)',\n                  background: '#fff',\n                  border: '1px solid #e5e7eb',\n                  borderRadius: '50%',\n                  width: '44px',\n                  height: '44px',\n                  cursor: 'pointer',\n                  display: 'flex',\n                  alignItems: 'center',\n                  justifyContent: 'center',\n                }}\n              >\n                <ChevronLeft size={20} />\n              </button>\n              <button\n                onClick={nextSlide}\n                style={{\n                  position: 'absolute',\n                  right: '-60px',\n                  top: '50%',\n                  transform: 'translateY(-50%)',\n                  background: '#fff',\n                  border: '1px solid #e5e7eb',\n                  borderRadius: '50%',\n                  width: '44px',\n                  height: '44px',\n                  cursor: 'pointer',\n                  display: 'flex',\n                  alignItems: 'center',\n                  justifyContent: 'center',\n                }}\n              >\n                <ChevronRight size={20} />\n              </button>\n\n              {/* Dots */}\n              <div style={{ \n                display: 'flex', \n                justifyContent: 'center', \n                gap: '0.5rem',\n                marginTop: '2rem',\n              }}>\n                {items.map((_, idx) => (\n                  <button\n                    key={idx}\n                    onClick={() => setCurrentIndex(idx)}\n                    style={{\n                      width: '10px',\n                      height: '10px',\n                      borderRadius: '50%',\n                      border: 'none',\n                      background: idx === currentIndex ? '#4f46e5' : '#d1d5db',\n                      cursor: 'pointer',\n                      padding: 0,\n                    }}\n                  />\n                ))}\n              </div>\n            </>\n          )}\n        </div>\n      ) : (\n        <div \n          className=\"testimonials-grid\"\n          style={{\n            display: 'grid',\n            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',\n            gap: '2rem',\n            maxWidth: '1200px',\n            margin: '0 auto',\n          }}\n        >\n          {items.map((item, idx) => (\n            <TestimonialCard key={item.id || idx} {...item} />\n          ))}\n        </div>\n      )}\n    </section>\n  );\n};\n\n/**\n * Testimonial Card Component\n */\nconst TestimonialCard = ({\n  quote,\n  authorName,\n  authorTitle,\n  authorCompany,\n  authorImage,\n  rating,\n}) => {\n  const imageUrl = authorImage?.data?.attributes?.url || authorImage?.url;\n\n  return (\n    <div \n      className=\"testimonial-card\"\n      style={{\n        background: '#fff',\n        borderRadius: '16px',\n        padding: '2rem',\n        boxShadow: '0 4px 20px rgba(0,0,0,0.08)',\n      }}\n    >\n      {rating && (\n        <div style={{ display: 'flex', gap: '0.25rem', marginBottom: '1rem' }}>\n          {[...Array(5)].map((_, i) => (\n            <Star \n              key={i}\n              size={18}\n              fill={i < rating ? '#f59e0b' : 'none'}\n              color={i < rating ? '#f59e0b' : '#d1d5db'}\n            />\n          ))}\n        </div>\n      )}\n\n      <p style={{ \n        fontSize: '1.1rem',\n        lineHeight: 1.7,\n        color: '#374151',\n        marginBottom: '1.5rem',\n        fontStyle: 'italic',\n      }}>\n        \"{quote}\"\n      </p>\n\n      <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>\n        {imageUrl ? (\n          <img \n            src={imageUrl}\n            alt={authorName}\n            style={{\n              width: '50px',\n              height: '50px',\n              borderRadius: '50%',\n              objectFit: 'cover',\n            }}\n          />\n        ) : (\n          <div style={{\n            width: '50px',\n            height: '50px',\n            borderRadius: '50%',\n            background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)',\n            display: 'flex',\n            alignItems: 'center',\n            justifyContent: 'center',\n            color: '#fff',\n            fontWeight: 600,\n          }}>\n            {authorName?.[0]?.toUpperCase()}\n          </div>\n        )}\n        \n        <div>\n          <div style={{ fontWeight: 600, color: '#1f2937' }}>{authorName}</div>\n          {(authorTitle || authorCompany) && (\n            <div style={{ fontSize: '0.9rem', color: '#6b7280' }}>\n              {authorTitle}{authorTitle && authorCompany && ', '}{authorCompany}\n            </div>\n          )}\n        </div>\n      </div>\n    </div>\n  );\n};\n\nexport default Testimonials;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport * as Icons from 'lucide-react';\n\n/**\n * Timeline Section Component\n */\nconst Timeline = ({\n  title,\n  orientation = 'vertical',\n  items = [],\n  accentColor = '#4f46e5',\n  backgroundColor = '#ffffff',\n  className = '',\n}) => {\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  return (\n    <section className={clsx('timeline-section', className)} style={containerStyle}>\n      {title && (\n        <h2 style={{ \n          textAlign: 'center', \n          fontSize: '2.5rem', \n          marginBottom: '3rem',\n        }}>\n          {title}\n        </h2>\n      )}\n\n      <div \n        className=\"timeline\"\n        style={{\n          maxWidth: '800px',\n          margin: '0 auto',\n          position: 'relative',\n        }}\n      >\n        {/* Vertical Line */}\n        <div\n          style={{\n            position: 'absolute',\n            left: '50%',\n            transform: 'translateX(-50%)',\n            width: '2px',\n            height: '100%',\n            background: '#e5e7eb',\n          }}\n        />\n\n        {items.map((item, index) => (\n          <TimelineItem \n            key={item.id || index}\n            {...item}\n            index={index}\n            accentColor={accentColor}\n          />\n        ))}\n      </div>\n    </section>\n  );\n};\n\n/**\n * Timeline Item Component\n */\nconst TimelineItem = ({\n  title,\n  description,\n  date,\n  icon,\n  image,\n  index,\n  accentColor,\n}) => {\n  const isEven = index % 2 === 0;\n  const IconComponent = icon && Icons[icon];\n  const imageUrl = image?.data?.attributes?.url || image?.url;\n\n  return (\n    <div\n      className=\"timeline-item\"\n      style={{\n        display: 'flex',\n        justifyContent: isEven ? 'flex-start' : 'flex-end',\n        paddingLeft: isEven ? 0 : '50%',\n        paddingRight: isEven ? '50%' : 0,\n        marginBottom: '3rem',\n        position: 'relative',\n      }}\n    >\n      {/* Dot */}\n      <div\n        style={{\n          position: 'absolute',\n          left: '50%',\n          transform: 'translateX(-50%)',\n          width: '40px',\n          height: '40px',\n          borderRadius: '50%',\n          background: accentColor,\n          display: 'flex',\n          alignItems: 'center',\n          justifyContent: 'center',\n          color: '#fff',\n          zIndex: 1,\n        }}\n      >\n        {IconComponent ? (\n          <IconComponent size={20} />\n        ) : (\n          <span style={{ fontWeight: 600 }}>{index + 1}</span>\n        )}\n      </div>\n\n      {/* Content */}\n      <div\n        style={{\n          background: '#fff',\n          borderRadius: '12px',\n          padding: '1.5rem',\n          boxShadow: '0 4px 15px rgba(0,0,0,0.08)',\n          marginLeft: isEven ? 0 : '2rem',\n          marginRight: isEven ? '2rem' : 0,\n          maxWidth: 'calc(50% - 40px)',\n          width: '100%',\n        }}\n      >\n        {date && (\n          <div style={{ \n            color: accentColor, \n            fontWeight: 600, \n            fontSize: '0.9rem',\n            marginBottom: '0.5rem',\n          }}>\n            {date}\n          </div>\n        )}\n\n        <h3 style={{ fontSize: '1.25rem', marginBottom: '0.5rem', fontWeight: 600 }}>\n          {title}\n        </h3>\n\n        {imageUrl && (\n          <img\n            src={imageUrl}\n            alt={title}\n            style={{\n              width: '100%',\n              borderRadius: '8px',\n              marginBottom: '0.75rem',\n            }}\n          />\n        )}\n\n        {description && (\n          <div \n            style={{ color: '#4b5563', lineHeight: 1.6 }}\n            dangerouslySetInnerHTML={{ __html: description }}\n          />\n        )}\n      </div>\n    </div>\n  );\n};\n\nexport default Timeline;\n\n","import React, { useState } from 'react';\nimport clsx from 'clsx';\nimport { Play } from 'lucide-react';\n\n/**\n * Video Embed Section Component\n */\nconst VideoEmbed = ({\n  title,\n  description,\n  videoUrl,\n  videoType = 'youtube',\n  autoplay = false,\n  loop = false,\n  muted = false,\n  posterImage,\n  aspectRatio = '16:9',\n  className = '',\n}) => {\n  const [showVideo, setShowVideo] = useState(autoplay);\n\n  const aspectRatioMap = {\n    '16:9': '56.25%',\n    '4:3': '75%',\n    '1:1': '100%',\n    '21:9': '42.86%',\n  };\n\n  const posterUrl = posterImage?.data?.attributes?.url || posterImage?.url;\n\n  /**\n   * Get embed URL based on video type\n   */\n  const getEmbedUrl = () => {\n    if (!videoUrl) return null;\n\n    const params = new URLSearchParams();\n    if (autoplay || showVideo) params.append('autoplay', '1');\n    if (loop) params.append('loop', '1');\n    if (muted) params.append('mute', '1');\n\n    switch (videoType) {\n      case 'youtube': {\n        // Extract video ID from various YouTube URL formats\n        const match = videoUrl.match(/(?:youtube\\.com\\/(?:watch\\?v=|embed\\/)|youtu\\.be\\/)([^&?/]+)/);\n        const videoId = match ? match[1] : videoUrl;\n        return `https://www.youtube.com/embed/${videoId}?${params.toString()}`;\n      }\n      case 'vimeo': {\n        const match = videoUrl.match(/vimeo\\.com\\/(\\d+)/);\n        const videoId = match ? match[1] : videoUrl;\n        return `https://player.vimeo.com/video/${videoId}?${params.toString()}`;\n      }\n      case 'embed':\n        return videoUrl;\n      default:\n        return videoUrl;\n    }\n  };\n\n  const handlePlayClick = () => {\n    setShowVideo(true);\n  };\n\n  return (\n    <section className={clsx('video-embed-section', className)} style={{ padding: '4rem 2rem' }}>\n      <div style={{ maxWidth: '900px', margin: '0 auto' }}>\n        {(title || description) && (\n          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>\n            {title && <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>{title}</h2>}\n            {description && <p style={{ fontSize: '1.1rem', opacity: 0.8 }}>{description}</p>}\n          </div>\n        )}\n\n        <div\n          style={{\n            position: 'relative',\n            paddingBottom: aspectRatioMap[aspectRatio],\n            height: 0,\n            overflow: 'hidden',\n            borderRadius: '12px',\n            background: '#000',\n          }}\n        >\n          {videoType === 'mp4' ? (\n            <video\n              src={videoUrl}\n              autoPlay={autoplay}\n              loop={loop}\n              muted={muted}\n              controls\n              poster={posterUrl}\n              style={{\n                position: 'absolute',\n                top: 0,\n                left: 0,\n                width: '100%',\n                height: '100%',\n              }}\n            />\n          ) : showVideo ? (\n            <iframe\n              src={getEmbedUrl()}\n              title={title || 'Video'}\n              frameBorder=\"0\"\n              allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\"\n              allowFullScreen\n              style={{\n                position: 'absolute',\n                top: 0,\n                left: 0,\n                width: '100%',\n                height: '100%',\n              }}\n            />\n          ) : (\n            <div\n              onClick={handlePlayClick}\n              style={{\n                position: 'absolute',\n                top: 0,\n                left: 0,\n                width: '100%',\n                height: '100%',\n                backgroundImage: posterUrl ? `url(${posterUrl})` : undefined,\n                backgroundSize: 'cover',\n                backgroundPosition: 'center',\n                cursor: 'pointer',\n                display: 'flex',\n                alignItems: 'center',\n                justifyContent: 'center',\n              }}\n            >\n              <div\n                style={{\n                  width: '80px',\n                  height: '80px',\n                  borderRadius: '50%',\n                  background: 'rgba(255,255,255,0.9)',\n                  display: 'flex',\n                  alignItems: 'center',\n                  justifyContent: 'center',\n                  transition: 'transform 0.2s',\n                }}\n              >\n                <Play size={36} fill=\"#4f46e5\" color=\"#4f46e5\" style={{ marginLeft: '4px' }} />\n              </div>\n            </div>\n          )}\n        </div>\n      </div>\n    </section>\n  );\n};\n\nexport default VideoEmbed;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport ReactMarkdown from 'react-markdown';\nimport rehypeRaw from 'rehype-raw';\n\n/**\n * Content Block Section Component.\n *\n * Strapi `layout.content` schema names the heading field `heading` but\n * earlier versions of this component (and its consumers) used `title`.\n * Accept both — `title` wins if both are passed — so neither rename\n * breaks rendering.\n */\nconst ContentBlock = ({\n  title,\n  heading,\n  content,\n  body, // legacy alias from older seed scripts; treated as `content`\n  backgroundColor = '#ffffff',\n  textColor = '#333333',\n  maxWidth = 'medium',\n  padding = 'medium',\n  alignment = 'left',\n  className = '',\n}) => {\n  const resolvedTitle = title || heading;\n  const resolvedContent = content || body;\n  const maxWidthMap = {\n    small: '600px',\n    medium: '800px',\n    large: '1000px',\n    full: '100%',\n  };\n\n  const paddingMap = {\n    none: '0',\n    small: '2rem',\n    medium: '4rem',\n    large: '6rem',\n  };\n\n  const containerStyle = {\n    background: backgroundColor,\n    color: textColor,\n    padding: `${paddingMap[padding]} 2rem`,\n  };\n\n  const contentStyle = {\n    maxWidth: maxWidthMap[maxWidth],\n    margin: '0 auto',\n    textAlign: alignment,\n  };\n\n  return (\n    <section className={clsx('content-block-section', className)} style={containerStyle}>\n      <div style={contentStyle}>\n        {resolvedTitle && (\n          <h2 style={{\n            fontSize: '2rem',\n            marginBottom: '1.5rem',\n            fontWeight: 700,\n          }}>\n            {resolvedTitle}\n          </h2>\n        )}\n\n        <div\n          className=\"content-body\"\n          style={{\n            lineHeight: 1.8,\n            fontSize: '1.1rem',\n          }}\n        >\n          <ReactMarkdown rehypePlugins={[rehypeRaw]}>\n            {resolvedContent || ''}\n          </ReactMarkdown>\n        </div>\n      </div>\n    </section>\n  );\n};\n\nexport default ContentBlock;\n\n","import React, { useEffect, useRef } from 'react';\nimport clsx from 'clsx';\n\n/**\n * Custom HTML Section Component\n * Renders raw HTML/CSS/JS - use with caution in production!\n */\nconst CustomHTML = ({\n  html,\n  css,\n  javascript,\n  containerClass = '',\n  sandboxed = true,\n  className = '',\n}) => {\n  const containerRef = useRef(null);\n\n  useEffect(() => {\n    if (!containerRef.current) return;\n\n    // Inject CSS\n    if (css) {\n      const styleElement = document.createElement('style');\n      styleElement.textContent = css;\n      containerRef.current.appendChild(styleElement);\n    }\n\n    // Execute JavaScript (only if not sandboxed)\n    if (javascript && !sandboxed) {\n      try {\n        const scriptElement = document.createElement('script');\n        scriptElement.textContent = javascript;\n        containerRef.current.appendChild(scriptElement);\n      } catch (error) {\n        console.error('Error executing custom JavaScript:', error);\n      }\n    }\n\n    return () => {\n      // Cleanup\n      if (containerRef.current) {\n        const styles = containerRef.current.querySelectorAll('style');\n        const scripts = containerRef.current.querySelectorAll('script');\n        styles.forEach(s => s.remove());\n        scripts.forEach(s => s.remove());\n      }\n    };\n  }, [css, javascript, sandboxed]);\n\n  if (sandboxed) {\n    // Render in an iframe for sandboxing\n    const iframeContent = `\n      <!DOCTYPE html>\n      <html>\n        <head>\n          <style>${css || ''}</style>\n        </head>\n        <body>\n          ${html || ''}\n          <script>${javascript || ''}</script>\n        </body>\n      </html>\n    `;\n\n    return (\n      <section className={clsx('custom-html-section', containerClass, className)}>\n        <iframe\n          srcDoc={iframeContent}\n          sandbox=\"allow-scripts\"\n          style={{\n            width: '100%',\n            border: 'none',\n            minHeight: '200px',\n          }}\n          title=\"Custom Content\"\n        />\n      </section>\n    );\n  }\n\n  return (\n    <section \n      ref={containerRef}\n      className={clsx('custom-html-section', containerClass, className)}\n      dangerouslySetInnerHTML={{ __html: html || '' }}\n    />\n  );\n};\n\nexport default CustomHTML;\n\n","import React, { createContext, useContext, useState, useCallback } from 'react';\n\n/**\n * Strapi Context - Provides Strapi configuration and site-scoped data fetching.\n *\n * siteSlug scopes ALL queries to a specific site. This is what makes the same\n * component library work for multiple websites — each site sets its own slug\n * and only sees its own content from a shared Strapi instance.\n */\nconst StrapiContext = createContext(null);\n\nexport const StrapiProvider = ({\n  children,\n  apiUrl,\n  apiToken = null,\n  siteSlug = null,\n  cacheTime = 60000 // 1 minute default cache\n}) => {\n  const [cache, setCache] = useState({});\n\n  /**\n   * Fetch data from Strapi API with caching\n   */\n  const fetchFromStrapi = useCallback(async (endpoint, options = {}) => {\n    const cacheKey = `${siteSlug || ''}:${endpoint}:${JSON.stringify(options)}`;\n    const now = Date.now();\n\n    // Check cache\n    if (cache[cacheKey] && (now - cache[cacheKey].timestamp) < cacheTime) {\n      return cache[cacheKey].data;\n    }\n\n    const headers = {\n      'Content-Type': 'application/json',\n    };\n\n    if (apiToken) {\n      headers['Authorization'] = `Bearer ${apiToken}`;\n    }\n\n    const response = await fetch(`${apiUrl}/api/${endpoint}`, {\n      headers,\n      ...options,\n    });\n\n    if (!response.ok) {\n      throw new Error(`Strapi API error: ${response.status}`);\n    }\n\n    const data = await response.json();\n\n    // Update cache\n    setCache(prev => ({\n      ...prev,\n      [cacheKey]: { data, timestamp: now }\n    }));\n\n    return data;\n  }, [apiUrl, apiToken, siteSlug, cacheTime, cache]);\n\n  /**\n   * Fetch a page by its pageType enum, scoped to the current site.\n   *\n   * Query:\n   *   GET /api/pages?filters[pageType][$eq]=home&filters[site][slug][$eq]=vaadhlabs\n   *       &populate[layout][populate]=*&populate[metadata]=*\n   */\n  const fetchPage = useCallback(async (pageType) => {\n    let endpoint = `pages?filters[pageType][$eq]=${pageType}`;\n\n    if (siteSlug) {\n      endpoint += `&filters[site][slug][$eq]=${siteSlug}`;\n    }\n\n    endpoint += '&populate[layout][populate]=*&populate[metadata]=*';\n\n    const data = await fetchFromStrapi(endpoint);\n    return data?.data?.[0] || null;\n  }, [fetchFromStrapi, siteSlug]);\n\n  /**\n   * Fetch a custom page by its customSlug, scoped to the current site.\n   */\n  const fetchCustomPage = useCallback(async (slug) => {\n    let endpoint = `pages?filters[pageType][$eq]=custom&filters[customSlug][$eq]=${slug}`;\n\n    if (siteSlug) {\n      endpoint += `&filters[site][slug][$eq]=${siteSlug}`;\n    }\n\n    endpoint += '&populate[layout][populate]=*&populate[metadata]=*';\n\n    const data = await fetchFromStrapi(endpoint);\n    return data?.data?.[0] || null;\n  }, [fetchFromStrapi, siteSlug]);\n\n  /**\n   * Fetch all pages for the current site (navigation/sitemap).\n   */\n  const fetchAllPages = useCallback(async () => {\n    let endpoint = 'pages?fields[0]=title&fields[1]=pageType&fields[2]=customSlug&fields[3]=isActive&sort=title:asc';\n\n    if (siteSlug) {\n      endpoint += `&filters[site][slug][$eq]=${siteSlug}`;\n    }\n\n    const data = await fetchFromStrapi(endpoint);\n    return data?.data || [];\n  }, [fetchFromStrapi, siteSlug]);\n\n  /**\n   * Fetch site configuration (branding, navigation, footer, integrations, emailConfig).\n   */\n  const fetchSiteConfig = useCallback(async () => {\n    if (!siteSlug) return null;\n\n    const endpoint = `sites?filters[slug][$eq]=${siteSlug}`\n      + '&populate[brandColors]=*'\n      + '&populate[navigation]=*'\n      + '&populate[footer][populate]=columns.links'\n      + '&populate[integrations]=*'\n      + '&populate[emailConfig]=*';\n\n    const data = await fetchFromStrapi(endpoint);\n    return data?.data?.[0] || null;\n  }, [fetchFromStrapi, siteSlug]);\n\n  /**\n   * Submit a form (contact, lead, demo, newsletter, support).\n   *\n   * Uses the custom public endpoint:\n   *   POST /api/form-submissions/submit\n   */\n  const submitForm = useCallback(async (formData) => {\n    const response = await fetch(`${apiUrl}/api/form-submissions/submit`, {\n      method: 'POST',\n      headers: { 'Content-Type': 'application/json' },\n      body: JSON.stringify({\n        ...formData,\n        siteSlug,\n      }),\n    });\n\n    if (!response.ok) {\n      const error = await response.json().catch(() => ({}));\n      throw new Error(error?.error?.message || `Submission failed: ${response.status}`);\n    }\n\n    return response.json();\n  }, [apiUrl, siteSlug]);\n\n  /**\n   * Clear cache\n   */\n  const clearCache = useCallback((endpoint = null) => {\n    if (endpoint) {\n      setCache(prev => {\n        const newCache = { ...prev };\n        Object.keys(newCache).forEach(key => {\n          if (key.includes(endpoint)) {\n            delete newCache[key];\n          }\n        });\n        return newCache;\n      });\n    } else {\n      setCache({});\n    }\n  }, []);\n\n  const value = {\n    apiUrl,\n    siteSlug,\n    fetchFromStrapi,\n    fetchPage,\n    fetchCustomPage,\n    fetchAllPages,\n    fetchSiteConfig,\n    submitForm,\n    clearCache,\n  };\n\n  return (\n    <StrapiContext.Provider value={value}>\n      {children}\n    </StrapiContext.Provider>\n  );\n};\n\nexport const useStrapi = () => {\n  const context = useContext(StrapiContext);\n  if (!context) {\n    throw new Error('useStrapi must be used within a StrapiProvider');\n  }\n  return context;\n};\n\nexport default StrapiContext;\n","import React, { useState, useEffect, useMemo } from 'react';\nimport clsx from 'clsx';\nimport { ChevronUp, ChevronDown, Search, ChevronLeft, ChevronRight } from 'lucide-react';\nimport { useStrapi } from '../../context/StrapiContext';\n\n/**\n * Data Table Section Component\n */\nconst DataTable = ({\n  title,\n  description,\n  dataSource = 'static',\n  apiEndpoint,\n  strapiCollection,\n  columns = [],\n  staticData = [],\n  enableSearch = true,\n  enableSort = true,\n  enablePagination = true,\n  pageSize = 10,\n  className = '',\n}) => {\n  const [data, setData] = useState([]);\n  const [loading, setLoading] = useState(false);\n  const [searchTerm, setSearchTerm] = useState('');\n  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });\n  const [currentPage, setCurrentPage] = useState(1);\n\n  const { fetchFromStrapi } = dataSource === 'strapi' ? useStrapi() : { fetchFromStrapi: null };\n\n  // Load data based on source\n  useEffect(() => {\n    const loadData = async () => {\n      setLoading(true);\n      try {\n        switch (dataSource) {\n          case 'static':\n            setData(staticData || []);\n            break;\n          case 'api':\n            if (apiEndpoint) {\n              const response = await fetch(apiEndpoint);\n              const result = await response.json();\n              setData(Array.isArray(result) ? result : result.data || []);\n            }\n            break;\n          case 'strapi':\n            if (strapiCollection && fetchFromStrapi) {\n              const result = await fetchFromStrapi(strapiCollection);\n              const items = result?.data?.map(item => ({\n                id: item.id,\n                ...item.attributes,\n              })) || [];\n              setData(items);\n            }\n            break;\n          default:\n            setData([]);\n        }\n      } catch (error) {\n        console.error('Error loading table data:', error);\n        setData([]);\n      } finally {\n        setLoading(false);\n      }\n    };\n\n    loadData();\n  }, [dataSource, apiEndpoint, strapiCollection, staticData, fetchFromStrapi]);\n\n  // Filter data by search term\n  const filteredData = useMemo(() => {\n    if (!searchTerm) return data;\n    \n    return data.filter(row => \n      columns.some(col => {\n        const value = row[col.key];\n        return String(value).toLowerCase().includes(searchTerm.toLowerCase());\n      })\n    );\n  }, [data, searchTerm, columns]);\n\n  // Sort data\n  const sortedData = useMemo(() => {\n    if (!sortConfig.key) return filteredData;\n\n    return [...filteredData].sort((a, b) => {\n      const aValue = a[sortConfig.key];\n      const bValue = b[sortConfig.key];\n\n      if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;\n      if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;\n      return 0;\n    });\n  }, [filteredData, sortConfig]);\n\n  // Paginate data\n  const paginatedData = useMemo(() => {\n    if (!enablePagination) return sortedData;\n    \n    const start = (currentPage - 1) * pageSize;\n    return sortedData.slice(start, start + pageSize);\n  }, [sortedData, currentPage, pageSize, enablePagination]);\n\n  const totalPages = Math.ceil(sortedData.length / pageSize);\n\n  const handleSort = (key) => {\n    if (!enableSort) return;\n    \n    setSortConfig(prev => ({\n      key,\n      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc',\n    }));\n  };\n\n  const formatValue = (value, column) => {\n    if (value === null || value === undefined) return '-';\n\n    switch (column.type) {\n      case 'date':\n        return new Date(value).toLocaleDateString();\n      case 'currency':\n        return new Intl.NumberFormat('en-US', { \n          style: 'currency', \n          currency: 'USD' \n        }).format(value);\n      case 'boolean':\n        return value ? '✓' : '✗';\n      case 'link':\n        return <a href={value} target=\"_blank\" rel=\"noopener noreferrer\">{value}</a>;\n      case 'badge':\n        return (\n          <span style={{\n            padding: '0.25rem 0.75rem',\n            borderRadius: '9999px',\n            fontSize: '0.875rem',\n            background: '#e0e7ff',\n            color: '#4338ca',\n          }}>\n            {value}\n          </span>\n        );\n      default:\n        return String(value);\n    }\n  };\n\n  return (\n    <section className={clsx('data-table-section', className)} style={{ padding: '4rem 2rem' }}>\n      <div style={{ maxWidth: '1200px', margin: '0 auto' }}>\n        {(title || description) && (\n          <div style={{ marginBottom: '2rem' }}>\n            {title && <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>{title}</h2>}\n            {description && <p style={{ color: '#6b7280' }}>{description}</p>}\n          </div>\n        )}\n\n        {/* Search */}\n        {enableSearch && (\n          <div style={{ marginBottom: '1.5rem', maxWidth: '300px' }}>\n            <div style={{ position: 'relative' }}>\n              <Search \n                size={20} \n                style={{ \n                  position: 'absolute', \n                  left: '1rem', \n                  top: '50%', \n                  transform: 'translateY(-50%)',\n                  color: '#9ca3af',\n                }} \n              />\n              <input\n                type=\"text\"\n                placeholder=\"Search...\"\n                value={searchTerm}\n                onChange={(e) => setSearchTerm(e.target.value)}\n                style={{\n                  width: '100%',\n                  padding: '0.75rem 1rem 0.75rem 3rem',\n                  border: '2px solid #e5e7eb',\n                  borderRadius: '8px',\n                  fontSize: '1rem',\n                  outline: 'none',\n                }}\n              />\n            </div>\n          </div>\n        )}\n\n        {/* Table */}\n        <div style={{ overflowX: 'auto', borderRadius: '8px', border: '1px solid #e5e7eb' }}>\n          <table style={{ width: '100%', borderCollapse: 'collapse' }}>\n            <thead>\n              <tr style={{ background: '#f9fafb' }}>\n                {columns.map((column) => (\n                  <th\n                    key={column.key}\n                    onClick={() => column.sortable !== false && handleSort(column.key)}\n                    style={{\n                      padding: '1rem',\n                      textAlign: 'left',\n                      fontWeight: 600,\n                      color: '#374151',\n                      borderBottom: '1px solid #e5e7eb',\n                      cursor: enableSort && column.sortable !== false ? 'pointer' : 'default',\n                      whiteSpace: 'nowrap',\n                      width: column.width,\n                    }}\n                  >\n                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>\n                      {column.label}\n                      {enableSort && column.sortable !== false && sortConfig.key === column.key && (\n                        sortConfig.direction === 'asc' ? \n                          <ChevronUp size={16} /> : \n                          <ChevronDown size={16} />\n                      )}\n                    </div>\n                  </th>\n                ))}\n              </tr>\n            </thead>\n            <tbody>\n              {loading ? (\n                <tr>\n                  <td colSpan={columns.length} style={{ padding: '2rem', textAlign: 'center' }}>\n                    Loading...\n                  </td>\n                </tr>\n              ) : paginatedData.length === 0 ? (\n                <tr>\n                  <td colSpan={columns.length} style={{ padding: '2rem', textAlign: 'center', color: '#6b7280' }}>\n                    No data available\n                  </td>\n                </tr>\n              ) : (\n                paginatedData.map((row, rowIndex) => (\n                  <tr \n                    key={row.id || rowIndex}\n                    style={{ \n                      background: rowIndex % 2 === 0 ? '#fff' : '#f9fafb',\n                      transition: 'background 0.2s',\n                    }}\n                    onMouseEnter={(e) => e.currentTarget.style.background = '#f0f9ff'}\n                    onMouseLeave={(e) => e.currentTarget.style.background = rowIndex % 2 === 0 ? '#fff' : '#f9fafb'}\n                  >\n                    {columns.map((column) => (\n                      <td\n                        key={column.key}\n                        style={{\n                          padding: '1rem',\n                          borderBottom: '1px solid #e5e7eb',\n                          color: '#4b5563',\n                        }}\n                      >\n                        {formatValue(row[column.key], column)}\n                      </td>\n                    ))}\n                  </tr>\n                ))\n              )}\n            </tbody>\n          </table>\n        </div>\n\n        {/* Pagination */}\n        {enablePagination && totalPages > 1 && (\n          <div style={{\n            display: 'flex',\n            justifyContent: 'space-between',\n            alignItems: 'center',\n            marginTop: '1.5rem',\n          }}>\n            <span style={{ color: '#6b7280', fontSize: '0.875rem' }}>\n              Showing {((currentPage - 1) * pageSize) + 1} to {Math.min(currentPage * pageSize, sortedData.length)} of {sortedData.length}\n            </span>\n\n            <div style={{ display: 'flex', gap: '0.5rem' }}>\n              <button\n                onClick={() => setCurrentPage(p => Math.max(1, p - 1))}\n                disabled={currentPage === 1}\n                style={{\n                  padding: '0.5rem',\n                  border: '1px solid #e5e7eb',\n                  borderRadius: '6px',\n                  background: '#fff',\n                  cursor: currentPage === 1 ? 'not-allowed' : 'pointer',\n                  opacity: currentPage === 1 ? 0.5 : 1,\n                }}\n              >\n                <ChevronLeft size={18} />\n              </button>\n              \n              {[...Array(totalPages)].map((_, i) => (\n                <button\n                  key={i}\n                  onClick={() => setCurrentPage(i + 1)}\n                  style={{\n                    padding: '0.5rem 0.75rem',\n                    border: '1px solid #e5e7eb',\n                    borderRadius: '6px',\n                    background: currentPage === i + 1 ? '#4f46e5' : '#fff',\n                    color: currentPage === i + 1 ? '#fff' : '#374151',\n                    cursor: 'pointer',\n                  }}\n                >\n                  {i + 1}\n                </button>\n              )).slice(Math.max(0, currentPage - 3), currentPage + 2)}\n              \n              <button\n                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}\n                disabled={currentPage === totalPages}\n                style={{\n                  padding: '0.5rem',\n                  border: '1px solid #e5e7eb',\n                  borderRadius: '6px',\n                  background: '#fff',\n                  cursor: currentPage === totalPages ? 'not-allowed' : 'pointer',\n                  opacity: currentPage === totalPages ? 0.5 : 1,\n                }}\n              >\n                <ChevronRight size={18} />\n              </button>\n            </div>\n          </div>\n        )}\n      </div>\n    </section>\n  );\n};\n\nexport default DataTable;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport { Check } from 'lucide-react';\n\n/**\n * Checkbox Component\n */\nconst Checkbox = ({\n  name,\n  label,\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  onChange,\n  onBlur,\n  className = '',\n}) => {\n  const isChecked = value === true || value === 'true' || value === 'on';\n\n  const handleChange = (e) => {\n    onChange?.(e.target.checked);\n  };\n\n  return (\n    <div className={clsx('form-field checkbox-field', className)}>\n      <label\n        style={{\n          display: 'flex',\n          alignItems: 'flex-start',\n          gap: '0.75rem',\n          cursor: disabled ? 'not-allowed' : 'pointer',\n          opacity: disabled ? 0.6 : 1,\n        }}\n      >\n        <div\n          style={{\n            position: 'relative',\n            flexShrink: 0,\n            marginTop: '0.125rem',\n          }}\n        >\n          <input\n            type=\"checkbox\"\n            id={name}\n            name={name}\n            checked={isChecked}\n            required={required}\n            disabled={disabled}\n            onChange={handleChange}\n            onBlur={onBlur}\n            style={{\n              position: 'absolute',\n              opacity: 0,\n              width: '20px',\n              height: '20px',\n              cursor: 'pointer',\n            }}\n          />\n          <div\n            style={{\n              width: '20px',\n              height: '20px',\n              borderRadius: '4px',\n              border: `2px solid ${error ? '#ef4444' : isChecked ? '#4f46e5' : '#d1d5db'}`,\n              background: isChecked ? '#4f46e5' : '#fff',\n              display: 'flex',\n              alignItems: 'center',\n              justifyContent: 'center',\n              transition: 'all 0.2s',\n            }}\n          >\n            {isChecked && <Check size={14} color=\"#fff\" strokeWidth={3} />}\n          </div>\n        </div>\n\n        <div>\n          <span style={{ color: '#374151' }}>\n            {label}\n            {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n          </span>\n          \n          {helpText && (\n            <p style={{\n              marginTop: '0.25rem',\n              fontSize: '0.875rem',\n              color: '#6b7280',\n            }}>\n              {helpText}\n            </p>\n          )}\n        </div>\n      </label>\n\n      {error && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: '#ef4444',\n        }}>\n          {error}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default Checkbox;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport { Calendar } from 'lucide-react';\n\n/**\n * Date Picker Component\n */\nconst DatePicker = ({\n  name,\n  label,\n  type = 'date', // date, time, datetime\n  placeholder,\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  onChange,\n  onBlur,\n  min,\n  max,\n  className = '',\n}) => {\n  const handleChange = (e) => {\n    onChange?.(e.target.value);\n  };\n\n  const inputType = type === 'datetime' ? 'datetime-local' : type;\n\n  const inputStyle = {\n    width: '100%',\n    padding: '0.75rem 2.5rem 0.75rem 1rem',\n    fontSize: '1rem',\n    border: `2px solid ${error ? '#ef4444' : '#e5e7eb'}`,\n    borderRadius: '8px',\n    outline: 'none',\n    transition: 'border-color 0.2s',\n    background: disabled ? '#f9fafb' : '#fff',\n  };\n\n  return (\n    <div className={clsx('form-field date-field', className)}>\n      {label && (\n        <label\n          htmlFor={name}\n          style={{\n            display: 'block',\n            marginBottom: '0.5rem',\n            fontWeight: 500,\n            color: '#374151',\n          }}\n        >\n          {label}\n          {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n        </label>\n      )}\n\n      <div style={{ position: 'relative' }}>\n        <input\n          id={name}\n          name={name}\n          type={inputType}\n          value={value || ''}\n          placeholder={placeholder}\n          required={required}\n          disabled={disabled}\n          min={min}\n          max={max}\n          onChange={handleChange}\n          onBlur={onBlur}\n          style={inputStyle}\n          onFocus={(e) => {\n            e.target.style.borderColor = '#4f46e5';\n          }}\n          onBlurCapture={(e) => {\n            e.target.style.borderColor = error ? '#ef4444' : '#e5e7eb';\n          }}\n        />\n\n        <Calendar\n          size={20}\n          style={{\n            position: 'absolute',\n            right: '1rem',\n            top: '50%',\n            transform: 'translateY(-50%)',\n            pointerEvents: 'none',\n            color: '#6b7280',\n          }}\n        />\n      </div>\n\n      {(error || helpText) && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: error ? '#ef4444' : '#6b7280',\n        }}>\n          {error || helpText}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default DatePicker;\n\n","import React, { useRef, useState } from 'react';\nimport clsx from 'clsx';\nimport { Upload, X, File } from 'lucide-react';\n\n/**\n * File Upload Component\n */\nconst FileUpload = ({\n  name,\n  label,\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  onChange,\n  onBlur,\n  accept,\n  multiple = false,\n  maxSize, // in MB\n  className = '',\n}) => {\n  const inputRef = useRef(null);\n  const [dragActive, setDragActive] = useState(false);\n  const [files, setFiles] = useState([]);\n\n  const handleFiles = (fileList) => {\n    const newFiles = Array.from(fileList);\n    \n    // Validate file size if maxSize is set\n    if (maxSize) {\n      const maxBytes = maxSize * 1024 * 1024;\n      const validFiles = newFiles.filter(file => file.size <= maxBytes);\n      if (validFiles.length !== newFiles.length) {\n        console.warn(`Some files exceed the ${maxSize}MB limit`);\n      }\n      setFiles(prev => multiple ? [...prev, ...validFiles] : validFiles);\n      onChange?.(multiple ? validFiles : validFiles[0]);\n    } else {\n      setFiles(prev => multiple ? [...prev, ...newFiles] : newFiles);\n      onChange?.(multiple ? newFiles : newFiles[0]);\n    }\n  };\n\n  const handleChange = (e) => {\n    if (e.target.files?.length) {\n      handleFiles(e.target.files);\n    }\n  };\n\n  const handleDrop = (e) => {\n    e.preventDefault();\n    setDragActive(false);\n    if (e.dataTransfer.files?.length) {\n      handleFiles(e.dataTransfer.files);\n    }\n  };\n\n  const handleDragOver = (e) => {\n    e.preventDefault();\n    setDragActive(true);\n  };\n\n  const handleDragLeave = () => {\n    setDragActive(false);\n  };\n\n  const removeFile = (index) => {\n    const newFiles = files.filter((_, i) => i !== index);\n    setFiles(newFiles);\n    onChange?.(multiple ? newFiles : newFiles[0] || null);\n  };\n\n  const dropzoneStyle = {\n    border: `2px dashed ${error ? '#ef4444' : dragActive ? '#4f46e5' : '#d1d5db'}`,\n    borderRadius: '8px',\n    padding: '2rem',\n    textAlign: 'center',\n    cursor: disabled ? 'not-allowed' : 'pointer',\n    background: dragActive ? '#f5f3ff' : disabled ? '#f9fafb' : '#fff',\n    transition: 'all 0.2s',\n  };\n\n  return (\n    <div className={clsx('form-field file-upload', className)}>\n      {label && (\n        <label\n          style={{\n            display: 'block',\n            marginBottom: '0.5rem',\n            fontWeight: 500,\n            color: '#374151',\n          }}\n        >\n          {label}\n          {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n        </label>\n      )}\n\n      <div\n        style={dropzoneStyle}\n        onClick={() => !disabled && inputRef.current?.click()}\n        onDrop={handleDrop}\n        onDragOver={handleDragOver}\n        onDragLeave={handleDragLeave}\n      >\n        <input\n          ref={inputRef}\n          type=\"file\"\n          id={name}\n          name={name}\n          accept={accept}\n          multiple={multiple}\n          disabled={disabled}\n          onChange={handleChange}\n          onBlur={onBlur}\n          style={{ display: 'none' }}\n        />\n\n        <Upload size={40} color=\"#9ca3af\" style={{ marginBottom: '1rem' }} />\n        <p style={{ color: '#374151', marginBottom: '0.5rem' }}>\n          Drag and drop files here, or click to browse\n        </p>\n        <p style={{ color: '#9ca3af', fontSize: '0.875rem' }}>\n          {accept ? `Accepted: ${accept}` : 'Any file type'}\n          {maxSize && ` (Max: ${maxSize}MB)`}\n        </p>\n      </div>\n\n      {/* File List */}\n      {files.length > 0 && (\n        <ul style={{ \n          listStyle: 'none', \n          padding: 0, \n          margin: '1rem 0 0 0',\n          display: 'flex',\n          flexDirection: 'column',\n          gap: '0.5rem',\n        }}>\n          {files.map((file, index) => (\n            <li\n              key={index}\n              style={{\n                display: 'flex',\n                alignItems: 'center',\n                gap: '0.75rem',\n                padding: '0.75rem',\n                background: '#f9fafb',\n                borderRadius: '6px',\n              }}\n            >\n              <File size={20} color=\"#6b7280\" />\n              <span style={{ flex: 1, color: '#374151' }}>{file.name}</span>\n              <span style={{ color: '#9ca3af', fontSize: '0.875rem' }}>\n                {(file.size / 1024).toFixed(1)} KB\n              </span>\n              <button\n                type=\"button\"\n                onClick={(e) => { e.stopPropagation(); removeFile(index); }}\n                style={{\n                  background: 'none',\n                  border: 'none',\n                  cursor: 'pointer',\n                  padding: '0.25rem',\n                }}\n              >\n                <X size={18} color=\"#ef4444\" />\n              </button>\n            </li>\n          ))}\n        </ul>\n      )}\n\n      {(error || helpText) && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: error ? '#ef4444' : '#6b7280',\n        }}>\n          {error || helpText}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default FileUpload;\n\n","import React, { useState } from 'react';\nimport clsx from 'clsx';\nimport Button from './Button';\n\n/**\n * Form Section Component - Renders CMS-driven forms and submits to Strapi.\n *\n * The `formType` field from Strapi (contact, lead, demo) determines\n * which type of form submission is created. The Strapi backend handles\n * storage and email notifications.\n *\n * Fields are defined in Strapi as a repeatable component (shared.form-field)\n * with name, label, type, and required attributes.\n */\nconst FormSection = ({\n  title,\n  description,\n  formType = 'contact',\n  fields = [],\n  submitButtonText = 'Submit',\n  successMessage = 'Thank you! We\\'ll be in touch soon.',\n  errorMessage = 'Something went wrong. Please try again.',\n  backgroundColor = '#ffffff',\n  onFormSubmit,\n  className = '',\n}) => {\n  const [formData, setFormData] = useState({});\n  const [submitting, setSubmitting] = useState(false);\n  const [submitted, setSubmitted] = useState(false);\n  const [error, setError] = useState(null);\n\n  const handleChange = (fieldName, value) => {\n    setFormData(prev => ({ ...prev, [fieldName]: value }));\n  };\n\n  const handleSubmit = async (e) => {\n    e.preventDefault();\n    setSubmitting(true);\n    setError(null);\n\n    try {\n      // Extract known fields, put the rest in extraData\n      const { name, email, company, phone, message, ...extraFields } = formData;\n\n      const payload = {\n        formType,\n        name: name || null,\n        email: email || formData.work_email || formData.workEmail,\n        company: company || null,\n        phone: phone || null,\n        message: message || null,\n        extraData: Object.keys(extraFields).length > 0 ? extraFields : null,\n        source: window.location.href,\n      };\n\n      if (onFormSubmit) {\n        await onFormSubmit(payload);\n      }\n\n      setSubmitted(true);\n    } catch (err) {\n      setError(err.message || errorMessage);\n    } finally {\n      setSubmitting(false);\n    }\n  };\n\n  const containerStyle = {\n    background: backgroundColor,\n    padding: '4rem 2rem',\n  };\n\n  if (submitted) {\n    return (\n      <section className={clsx('form-section', className)} style={containerStyle}>\n        <div style={{ maxWidth: '600px', margin: '0 auto', textAlign: 'center' }}>\n          <div style={{\n            background: '#f0fdf4',\n            border: '1px solid #bbf7d0',\n            borderRadius: '12px',\n            padding: '2rem',\n          }}>\n            <svg width=\"48\" height=\"48\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#22c55e\" strokeWidth=\"2\" style={{ margin: '0 auto 1rem' }}>\n              <path d=\"M22 11.08V12a10 10 0 1 1-5.93-9.14\" />\n              <polyline points=\"22 4 12 14.01 9 11.01\" />\n            </svg>\n            <p style={{ fontSize: '1.2rem', color: '#166534', fontWeight: 500 }}>{successMessage}</p>\n          </div>\n        </div>\n      </section>\n    );\n  }\n\n  return (\n    <section className={clsx('form-section', className)} style={containerStyle}>\n      <div style={{ maxWidth: '600px', margin: '0 auto' }}>\n        {(title || description) && (\n          <div style={{ textAlign: 'center', marginBottom: '2rem' }}>\n            {title && <h2 style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>{title}</h2>}\n            {description && <p style={{ fontSize: '1.1rem', color: '#6b7280' }}>{description}</p>}\n          </div>\n        )}\n\n        <form onSubmit={handleSubmit}>\n          {fields.map((field, idx) => (\n            <div key={field.name || idx} style={{ marginBottom: '1.25rem' }}>\n              {field.label && (\n                <label\n                  htmlFor={field.name}\n                  style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 500, color: '#374151' }}\n                >\n                  {field.label}\n                  {field.required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n                </label>\n              )}\n\n              {field.type === 'textarea' ? (\n                <textarea\n                  id={field.name}\n                  name={field.name}\n                  required={field.required}\n                  rows={4}\n                  value={formData[field.name] || ''}\n                  onChange={(e) => handleChange(field.name, e.target.value)}\n                  style={{\n                    width: '100%',\n                    padding: '0.75rem 1rem',\n                    border: '1px solid #d1d5db',\n                    borderRadius: '8px',\n                    fontSize: '1rem',\n                    resize: 'vertical',\n                    fontFamily: 'inherit',\n                  }}\n                />\n              ) : field.type === 'select' && field.options ? (\n                <select\n                  id={field.name}\n                  name={field.name}\n                  required={field.required}\n                  value={formData[field.name] || ''}\n                  onChange={(e) => handleChange(field.name, e.target.value)}\n                  style={{\n                    width: '100%',\n                    padding: '0.75rem 1rem',\n                    border: '1px solid #d1d5db',\n                    borderRadius: '8px',\n                    fontSize: '1rem',\n                    background: '#fff',\n                  }}\n                >\n                  <option value=\"\">Select...</option>\n                  {(Array.isArray(field.options) ? field.options : []).map((opt, i) => (\n                    <option key={i} value={opt.value || opt}>{opt.label || opt}</option>\n                  ))}\n                </select>\n              ) : (\n                <input\n                  id={field.name}\n                  name={field.name}\n                  type={field.type || 'text'}\n                  required={field.required}\n                  value={formData[field.name] || ''}\n                  onChange={(e) => handleChange(field.name, e.target.value)}\n                  style={{\n                    width: '100%',\n                    padding: '0.75rem 1rem',\n                    border: '1px solid #d1d5db',\n                    borderRadius: '8px',\n                    fontSize: '1rem',\n                  }}\n                />\n              )}\n            </div>\n          ))}\n\n          {error && (\n            <div style={{\n              background: '#fef2f2',\n              border: '1px solid #fecaca',\n              borderRadius: '8px',\n              padding: '0.75rem 1rem',\n              marginBottom: '1rem',\n              color: '#991b1b',\n              fontSize: '0.9rem',\n            }}>\n              {error}\n            </div>\n          )}\n\n          <Button\n            text={submitting ? 'Submitting...' : submitButtonText}\n            type=\"submit\"\n            variant=\"primary\"\n            disabled={submitting}\n          />\n        </form>\n      </div>\n    </section>\n  );\n};\n\nexport default FormSection;\n","import React from 'react';\nimport clsx from 'clsx';\n\n/**\n * Radio Group Component\n */\nconst RadioGroup = ({\n  name,\n  label,\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  options = [],\n  onChange,\n  onBlur,\n  className = '',\n}) => {\n  const handleChange = (optionValue) => {\n    if (!disabled) {\n      onChange?.(optionValue);\n    }\n  };\n\n  return (\n    <div className={clsx('form-field radio-group', className)}>\n      {label && (\n        <p style={{\n          marginBottom: '0.75rem',\n          fontWeight: 500,\n          color: '#374151',\n        }}>\n          {label}\n          {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n        </p>\n      )}\n\n      <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>\n        {options.map((option, index) => {\n          const isSelected = value === option.value;\n          \n          return (\n            <label\n              key={option.value || index}\n              style={{\n                display: 'flex',\n                alignItems: 'center',\n                gap: '0.75rem',\n                cursor: disabled || option.disabled ? 'not-allowed' : 'pointer',\n                opacity: disabled || option.disabled ? 0.6 : 1,\n              }}\n            >\n              <div style={{ position: 'relative', flexShrink: 0 }}>\n                <input\n                  type=\"radio\"\n                  name={name}\n                  value={option.value}\n                  checked={isSelected}\n                  disabled={disabled || option.disabled}\n                  onChange={() => handleChange(option.value)}\n                  onBlur={onBlur}\n                  style={{\n                    position: 'absolute',\n                    opacity: 0,\n                    width: '20px',\n                    height: '20px',\n                    cursor: 'pointer',\n                  }}\n                />\n                <div\n                  style={{\n                    width: '20px',\n                    height: '20px',\n                    borderRadius: '50%',\n                    border: `2px solid ${error ? '#ef4444' : isSelected ? '#4f46e5' : '#d1d5db'}`,\n                    background: '#fff',\n                    display: 'flex',\n                    alignItems: 'center',\n                    justifyContent: 'center',\n                    transition: 'all 0.2s',\n                  }}\n                >\n                  {isSelected && (\n                    <div\n                      style={{\n                        width: '10px',\n                        height: '10px',\n                        borderRadius: '50%',\n                        background: '#4f46e5',\n                      }}\n                    />\n                  )}\n                </div>\n              </div>\n\n              <span style={{ color: '#374151' }}>{option.label}</span>\n            </label>\n          );\n        })}\n      </div>\n\n      {(error || helpText) && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: error ? '#ef4444' : '#6b7280',\n        }}>\n          {error || helpText}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default RadioGroup;\n\n","import React from 'react';\nimport clsx from 'clsx';\nimport { ChevronDown } from 'lucide-react';\n\n/**\n * Select/Dropdown Component\n */\nconst Select = ({\n  name,\n  label,\n  placeholder = 'Select an option',\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  options = [],\n  multiple = false,\n  onChange,\n  onBlur,\n  className = '',\n}) => {\n  const handleChange = (e) => {\n    if (multiple) {\n      const selectedOptions = Array.from(e.target.selectedOptions, option => option.value);\n      onChange?.(selectedOptions);\n    } else {\n      onChange?.(e.target.value);\n    }\n  };\n\n  const selectStyle = {\n    width: '100%',\n    padding: '0.75rem 2.5rem 0.75rem 1rem',\n    fontSize: '1rem',\n    border: `2px solid ${error ? '#ef4444' : '#e5e7eb'}`,\n    borderRadius: '8px',\n    outline: 'none',\n    transition: 'border-color 0.2s',\n    background: disabled ? '#f9fafb' : '#fff',\n    appearance: 'none',\n    cursor: disabled ? 'not-allowed' : 'pointer',\n  };\n\n  return (\n    <div className={clsx('form-field select-field', className)}>\n      {label && (\n        <label\n          htmlFor={name}\n          style={{\n            display: 'block',\n            marginBottom: '0.5rem',\n            fontWeight: 500,\n            color: '#374151',\n          }}\n        >\n          {label}\n          {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n        </label>\n      )}\n\n      <div style={{ position: 'relative' }}>\n        <select\n          id={name}\n          name={name}\n          value={value || (multiple ? [] : '')}\n          required={required}\n          disabled={disabled}\n          multiple={multiple}\n          onChange={handleChange}\n          onBlur={onBlur}\n          style={selectStyle}\n          onFocus={(e) => {\n            e.target.style.borderColor = '#4f46e5';\n          }}\n          onBlurCapture={(e) => {\n            e.target.style.borderColor = error ? '#ef4444' : '#e5e7eb';\n          }}\n        >\n          {!multiple && (\n            <option value=\"\" disabled>\n              {placeholder}\n            </option>\n          )}\n          {options.map((option, index) => (\n            <option \n              key={option.value || index} \n              value={option.value}\n              disabled={option.disabled}\n            >\n              {option.label}\n            </option>\n          ))}\n        </select>\n\n        {!multiple && (\n          <ChevronDown\n            size={20}\n            style={{\n              position: 'absolute',\n              right: '1rem',\n              top: '50%',\n              transform: 'translateY(-50%)',\n              pointerEvents: 'none',\n              color: '#6b7280',\n            }}\n          />\n        )}\n      </div>\n\n      {(error || helpText) && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: error ? '#ef4444' : '#6b7280',\n        }}>\n          {error || helpText}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default Select;\n\n","import React from 'react';\nimport clsx from 'clsx';\n\n/**\n * Text Area Component\n */\nconst TextArea = ({\n  name,\n  label,\n  placeholder,\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  onChange,\n  onBlur,\n  rows = 4,\n  className = '',\n}) => {\n  const handleChange = (e) => {\n    onChange?.(e.target.value);\n  };\n\n  const textareaStyle = {\n    width: '100%',\n    padding: '0.75rem 1rem',\n    fontSize: '1rem',\n    border: `2px solid ${error ? '#ef4444' : '#e5e7eb'}`,\n    borderRadius: '8px',\n    outline: 'none',\n    transition: 'border-color 0.2s',\n    resize: 'vertical',\n    minHeight: '100px',\n    background: disabled ? '#f9fafb' : '#fff',\n    fontFamily: 'inherit',\n  };\n\n  return (\n    <div className={clsx('form-field textarea-field', className)}>\n      {label && (\n        <label\n          htmlFor={name}\n          style={{\n            display: 'block',\n            marginBottom: '0.5rem',\n            fontWeight: 500,\n            color: '#374151',\n          }}\n        >\n          {label}\n          {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n        </label>\n      )}\n\n      <textarea\n        id={name}\n        name={name}\n        value={value || ''}\n        placeholder={placeholder}\n        required={required}\n        disabled={disabled}\n        onChange={handleChange}\n        onBlur={onBlur}\n        rows={rows}\n        style={textareaStyle}\n        onFocus={(e) => {\n          e.target.style.borderColor = '#4f46e5';\n        }}\n        onBlurCapture={(e) => {\n          e.target.style.borderColor = error ? '#ef4444' : '#e5e7eb';\n        }}\n      />\n\n      {(error || helpText) && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: error ? '#ef4444' : '#6b7280',\n        }}>\n          {error || helpText}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default TextArea;\n\n","import React from 'react';\nimport clsx from 'clsx';\n\n/**\n * Text Field Component\n */\nconst TextField = ({\n  name,\n  label,\n  type = 'text',\n  placeholder,\n  helpText,\n  required = false,\n  disabled = false,\n  value,\n  error,\n  onChange,\n  onBlur,\n  className = '',\n}) => {\n  const handleChange = (e) => {\n    onChange?.(e.target.value);\n  };\n\n  const inputStyle = {\n    width: '100%',\n    padding: '0.75rem 1rem',\n    fontSize: '1rem',\n    border: `2px solid ${error ? '#ef4444' : '#e5e7eb'}`,\n    borderRadius: '8px',\n    outline: 'none',\n    transition: 'border-color 0.2s',\n    background: disabled ? '#f9fafb' : '#fff',\n  };\n\n  return (\n    <div className={clsx('form-field text-field', className)}>\n      {label && (\n        <label\n          htmlFor={name}\n          style={{\n            display: 'block',\n            marginBottom: '0.5rem',\n            fontWeight: 500,\n            color: '#374151',\n          }}\n        >\n          {label}\n          {required && <span style={{ color: '#ef4444', marginLeft: '0.25rem' }}>*</span>}\n        </label>\n      )}\n\n      <input\n        id={name}\n        name={name}\n        type={type}\n        value={value || ''}\n        placeholder={placeholder}\n        required={required}\n        disabled={disabled}\n        onChange={handleChange}\n        onBlur={onBlur}\n        style={inputStyle}\n        onFocus={(e) => {\n          e.target.style.borderColor = '#4f46e5';\n        }}\n        onBlurCapture={(e) => {\n          e.target.style.borderColor = error ? '#ef4444' : '#e5e7eb';\n        }}\n      />\n\n      {(error || helpText) && (\n        <p style={{\n          marginTop: '0.5rem',\n          fontSize: '0.875rem',\n          color: error ? '#ef4444' : '#6b7280',\n        }}>\n          {error || helpText}\n        </p>\n      )}\n    </div>\n  );\n};\n\nexport default TextField;\n\n","import { useState, useCallback } from 'react';\n\n/**\n * Hook for managing dynamic form state\n */\nexport const useForm = (fields, options = {}) => {\n  const { onSubmit, validateOnChange = false } = options;\n  \n  // Initialize form values from field defaults\n  const initialValues = fields.reduce((acc, field) => {\n    acc[field.name] = field.defaultValue || '';\n    return acc;\n  }, {});\n\n  const [values, setValues] = useState(initialValues);\n  const [errors, setErrors] = useState({});\n  const [touched, setTouched] = useState({});\n  const [submitting, setSubmitting] = useState(false);\n  const [submitted, setSubmitted] = useState(false);\n\n  /**\n   * Validate a single field\n   */\n  const validateField = useCallback((field, value) => {\n    if (field.required && !value) {\n      return `${field.label} is required`;\n    }\n\n    if (field.validation) {\n      const { minLength, maxLength, min, max, pattern, customMessage } = field.validation;\n\n      if (minLength && value.length < minLength) {\n        return customMessage || `${field.label} must be at least ${minLength} characters`;\n      }\n      if (maxLength && value.length > maxLength) {\n        return customMessage || `${field.label} must be at most ${maxLength} characters`;\n      }\n      if (min !== undefined && Number(value) < min) {\n        return customMessage || `${field.label} must be at least ${min}`;\n      }\n      if (max !== undefined && Number(value) > max) {\n        return customMessage || `${field.label} must be at most ${max}`;\n      }\n      if (pattern && !new RegExp(pattern).test(value)) {\n        return customMessage || `${field.label} format is invalid`;\n      }\n    }\n\n    // Type-specific validation\n    if (field.type === 'email' && value) {\n      const emailRegex = /^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$/;\n      if (!emailRegex.test(value)) {\n        return 'Please enter a valid email address';\n      }\n    }\n\n    return null;\n  }, []);\n\n  /**\n   * Validate all fields\n   */\n  const validateAll = useCallback(() => {\n    const newErrors = {};\n    fields.forEach(field => {\n      const error = validateField(field, values[field.name]);\n      if (error) {\n        newErrors[field.name] = error;\n      }\n    });\n    setErrors(newErrors);\n    return Object.keys(newErrors).length === 0;\n  }, [fields, values, validateField]);\n\n  /**\n   * Handle field change\n   */\n  const handleChange = useCallback((name, value) => {\n    setValues(prev => ({ ...prev, [name]: value }));\n    \n    if (validateOnChange && touched[name]) {\n      const field = fields.find(f => f.name === name);\n      if (field) {\n        const error = validateField(field, value);\n        setErrors(prev => ({ ...prev, [name]: error }));\n      }\n    }\n  }, [fields, touched, validateOnChange, validateField]);\n\n  /**\n   * Handle field blur\n   */\n  const handleBlur = useCallback((name) => {\n    setTouched(prev => ({ ...prev, [name]: true }));\n    \n    const field = fields.find(f => f.name === name);\n    if (field) {\n      const error = validateField(field, values[name]);\n      setErrors(prev => ({ ...prev, [name]: error }));\n    }\n  }, [fields, values, validateField]);\n\n  /**\n   * Handle form submit\n   */\n  const handleSubmit = useCallback(async (e) => {\n    e?.preventDefault();\n    \n    setTouched(fields.reduce((acc, f) => ({ ...acc, [f.name]: true }), {}));\n    \n    if (!validateAll()) {\n      return { success: false, errors };\n    }\n\n    setSubmitting(true);\n    \n    try {\n      if (onSubmit) {\n        await onSubmit(values);\n      }\n      setSubmitted(true);\n      return { success: true, data: values };\n    } catch (error) {\n      return { success: false, error };\n    } finally {\n      setSubmitting(false);\n    }\n  }, [fields, values, errors, onSubmit, validateAll]);\n\n  /**\n   * Reset form\n   */\n  const reset = useCallback(() => {\n    setValues(initialValues);\n    setErrors({});\n    setTouched({});\n    setSubmitted(false);\n  }, [initialValues]);\n\n  /**\n   * Check if field should be visible (conditional display)\n   */\n  const isFieldVisible = useCallback((field) => {\n    if (!field.conditionalDisplay) return true;\n\n    const { field: condField, operator, value: condValue, action } = field.conditionalDisplay;\n    const fieldValue = values[condField];\n\n    let conditionMet = false;\n    switch (operator) {\n      case 'equals':\n        conditionMet = fieldValue === condValue;\n        break;\n      case 'notEquals':\n        conditionMet = fieldValue !== condValue;\n        break;\n      case 'contains':\n        conditionMet = String(fieldValue).includes(condValue);\n        break;\n      case 'isEmpty':\n        conditionMet = !fieldValue;\n        break;\n      case 'isNotEmpty':\n        conditionMet = !!fieldValue;\n        break;\n      default:\n        conditionMet = true;\n    }\n\n    if (action === 'hide') return !conditionMet;\n    return conditionMet;\n  }, [values]);\n\n  return {\n    values,\n    errors,\n    touched,\n    submitting,\n    submitted,\n    handleChange,\n    handleBlur,\n    handleSubmit,\n    reset,\n    isFieldVisible,\n    setValues,\n  };\n};\n\nexport default useForm;\n\n","import { useState, useEffect } from 'react';\nimport { useStrapi } from '../context/StrapiContext';\n\n/**\n * Hook to fetch navigation/page structure\n */\nexport const useNavigation = () => {\n  const { fetchAllPages } = useStrapi();\n  const [pages, setPages] = useState([]);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useEffect(() => {\n    let mounted = true;\n\n    const loadPages = async () => {\n      try {\n        setLoading(true);\n        const data = await fetchAllPages();\n        if (mounted) {\n          // Build navigation tree\n          const tree = buildNavigationTree(data);\n          setPages(tree);\n        }\n      } catch (err) {\n        if (mounted) {\n          setError(err);\n        }\n      } finally {\n        if (mounted) {\n          setLoading(false);\n        }\n      }\n    };\n\n    loadPages();\n\n    return () => {\n      mounted = false;\n    };\n  }, [fetchAllPages]);\n\n  return { pages, loading, error };\n};\n\n/**\n * Build a tree structure from flat page list\n */\nconst buildNavigationTree = (pages) => {\n  const tree = [];\n  const map = {};\n\n  // First pass: create map\n  pages.forEach(page => {\n    const attrs = page.attributes || page;\n    map[page.id] = {\n      id: page.id,\n      title: attrs.title,\n      slug: attrs.slug,\n      order: attrs.order,\n      children: [],\n    };\n  });\n\n  // Second pass: build tree\n  pages.forEach(page => {\n    const attrs = page.attributes || page;\n    const parentSlug = attrs.parentPage?.data?.attributes?.slug;\n    \n    if (parentSlug) {\n      const parent = Object.values(map).find(p => p.slug === parentSlug);\n      if (parent) {\n        parent.children.push(map[page.id]);\n      }\n    } else {\n      tree.push(map[page.id]);\n    }\n  });\n\n  // Sort by order\n  const sortByOrder = (items) => {\n    items.sort((a, b) => a.order - b.order);\n    items.forEach(item => {\n      if (item.children.length > 0) {\n        sortByOrder(item.children);\n      }\n    });\n  };\n\n  sortByOrder(tree);\n\n  return tree;\n};\n\nexport default useNavigation;\n\n","import { useState, useEffect } from 'react';\nimport { useStrapi } from '../context/StrapiContext';\n\n/**\n * Page type enum values that map to URL paths.\n *\n * `products` maps to `/product` (singular). The Strapi pageType enum is\n * plural because Strapi conventions use plural collection-style names,\n * but the canonical URL is singular — most sites have one Product page,\n * not many.\n */\nconst PAGE_TYPE_ROUTES = {\n  home: '/',\n  pricing: '/pricing',\n  about: '/about',\n  contact: '/contact',\n  solutions: '/solutions',\n  products: '/product',\n  blog: '/blog',\n  careers: '/careers',\n  terms: '/terms',\n  privacy: '/privacy',\n};\n\n// Reverse-lookup: URL slug → pageType enum value.\nconst ROUTE_TO_PAGE_TYPE = Object.fromEntries(\n  Object.entries(PAGE_TYPE_ROUTES).map(([type, route]) => [\n    route.replace(/^\\//, '') || 'home',\n    type,\n  ])\n);\n\n/**\n * Resolve a URL path to a pageType enum value.\n *\n * \"/\" or \"\" → \"home\"\n * \"/pricing\" → \"pricing\"\n * \"/product\" → \"products\" (URL-singular, enum-plural)\n * \"/anything-else\" → treated as a customSlug\n */\nexport const resolvePageType = (path) => {\n  const clean = (path || '/').replace(/^\\/+|\\/+$/g, '') || 'home';\n\n  // Try the URL → pageType reverse map first (handles /product → products).\n  if (ROUTE_TO_PAGE_TYPE[clean] !== undefined) {\n    return { pageType: ROUTE_TO_PAGE_TYPE[clean], isCustom: false };\n  }\n\n  // Fallback: maybe the slug already IS the pageType (e.g. /blog).\n  if (PAGE_TYPE_ROUTES[clean] !== undefined) {\n    return { pageType: clean, isCustom: false };\n  }\n\n  // Otherwise treat as custom slug.\n  return { pageType: 'custom', isCustom: true, customSlug: clean };\n};\n\n/**\n * Get the URL path for a pageType.\n */\nexport const getPagePath = (pageType, customSlug) => {\n  if (pageType === 'custom' && customSlug) {\n    return `/${customSlug}`;\n  }\n  return PAGE_TYPE_ROUTES[pageType] || `/${pageType}`;\n};\n\n/**\n * Hook to fetch a page by its type or custom slug.\n *\n * Usage:\n *   const { page, loading, error } = usePage('pricing');\n *   const { page, loading, error } = usePage('home');\n *   const { page, loading, error } = usePage('custom', 'my-landing-page');\n */\nexport const usePage = (pageType, customSlug) => {\n  const { fetchPage, fetchCustomPage } = useStrapi();\n  const [page, setPage] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useEffect(() => {\n    if (!pageType) {\n      setLoading(false);\n      return;\n    }\n\n    let mounted = true;\n\n    const loadPage = async () => {\n      try {\n        setLoading(true);\n        setError(null);\n\n        let data;\n        if (pageType === 'custom' && customSlug) {\n          data = await fetchCustomPage(customSlug);\n        } else {\n          data = await fetchPage(pageType);\n        }\n\n        if (mounted) {\n          setPage(data);\n        }\n      } catch (err) {\n        if (mounted) {\n          setError(err);\n        }\n      } finally {\n        if (mounted) {\n          setLoading(false);\n        }\n      }\n    };\n\n    loadPage();\n\n    return () => {\n      mounted = false;\n    };\n  }, [pageType, customSlug, fetchPage, fetchCustomPage]);\n\n  return { page, loading, error };\n};\n\nexport default usePage;\n","import { useState, useEffect } from 'react';\nimport { useStrapi } from '../context/StrapiContext';\n\n/**\n * Hook to fetch and manage site configuration.\n *\n * Returns branding, navigation, footer, analytics integrations,\n * and email config for the current site.\n *\n * Usage:\n *   const { navigation, footer, brandColors, integrations, loading } = useSiteConfig();\n */\nexport const useSiteConfig = () => {\n  const { fetchSiteConfig, siteSlug } = useStrapi();\n  const [site, setSite] = useState(null);\n  const [loading, setLoading] = useState(true);\n  const [error, setError] = useState(null);\n\n  useEffect(() => {\n    if (!siteSlug) {\n      setLoading(false);\n      return;\n    }\n\n    let mounted = true;\n\n    const loadConfig = async () => {\n      try {\n        setLoading(true);\n        setError(null);\n        const data = await fetchSiteConfig();\n        if (mounted) {\n          setSite(data);\n        }\n      } catch (err) {\n        if (mounted) {\n          setError(err);\n        }\n      } finally {\n        if (mounted) {\n          setLoading(false);\n        }\n      }\n    };\n\n    loadConfig();\n\n    return () => {\n      mounted = false;\n    };\n  }, [siteSlug, fetchSiteConfig]);\n\n  const attrs = site?.attributes || site || {};\n\n  return {\n    site,\n    navigation: attrs.navigation || [],\n    footer: attrs.footer || null,\n    brandColors: attrs.brandColors || null,\n    integrations: attrs.integrations || null,\n    emailConfig: attrs.emailConfig || null,\n    logo: attrs.logo || null,\n    logoHeight: attrs.logoHeight || 36,\n    favicon: attrs.favicon || null,\n    siteName: attrs.name || '',\n    tagline: attrs.tagline || '',\n    domain: attrs.domain || '',\n    loading,\n    error,\n  };\n};\n\nexport default useSiteConfig;\n","import { useState, useCallback } from 'react';\nimport { useStrapi } from '../context/StrapiContext';\n\n/**\n * Hook for submitting forms to Strapi.\n *\n * Handles loading state, validation, and error handling.\n * The form data is stored in Strapi's FormSubmission collection\n * and an email notification is sent if the site has emailConfig.\n *\n * Usage:\n *   const { submit, loading, error, success } = useFormSubmission();\n *\n *   const handleSubmit = (e) => {\n *     e.preventDefault();\n *     submit({\n *       formType: 'contact',\n *       name: 'John Doe',\n *       email: 'john@example.com',\n *       message: 'Hello!',\n *     });\n *   };\n */\nexport const useFormSubmission = () => {\n  const { submitForm } = useStrapi();\n  const [loading, setLoading] = useState(false);\n  const [error, setError] = useState(null);\n  const [success, setSuccess] = useState(false);\n  const [submissionId, setSubmissionId] = useState(null);\n\n  const submit = useCallback(async (formData) => {\n    try {\n      setLoading(true);\n      setError(null);\n      setSuccess(false);\n\n      const result = await submitForm(formData);\n\n      setSubmissionId(result?.data?.id || null);\n      setSuccess(true);\n      return result;\n    } catch (err) {\n      setError(err);\n      throw err;\n    } finally {\n      setLoading(false);\n    }\n  }, [submitForm]);\n\n  const reset = useCallback(() => {\n    setLoading(false);\n    setError(null);\n    setSuccess(false);\n    setSubmissionId(null);\n  }, []);\n\n  return { submit, loading, error, success, submissionId, reset };\n};\n\nexport default useFormSubmission;\n","import { useEffect, useCallback, useRef } from 'react';\n\n/**\n * Hook that injects analytics scripts based on site integrations from Strapi.\n *\n * Supports:\n * - Google Analytics (GA4)\n * - Google Tag Manager\n * - Facebook Pixel\n * - Hotjar\n * - Custom head/body scripts\n *\n * Usage in App.js:\n *   const { integrations } = useSiteConfig();\n *   useAnalytics(integrations);\n */\nexport const useAnalytics = (integrations) => {\n  const injectedRef = useRef(false);\n\n  useEffect(() => {\n    if (!integrations || injectedRef.current) return;\n    injectedRef.current = true;\n\n    // --- Google Analytics (GA4) ---\n    if (integrations.googleAnalyticsId) {\n      const gaId = integrations.googleAnalyticsId;\n      const script = document.createElement('script');\n      script.async = true;\n      script.src = `https://www.googletagmanager.com/gtag/js?id=${gaId}`;\n      document.head.appendChild(script);\n\n      const inlineScript = document.createElement('script');\n      inlineScript.textContent = `\n        window.dataLayer = window.dataLayer || [];\n        function gtag(){dataLayer.push(arguments);}\n        gtag('js', new Date());\n        gtag('config', '${gaId}');\n      `;\n      document.head.appendChild(inlineScript);\n    }\n\n    // --- Google Tag Manager ---\n    if (integrations.googleTagManagerId) {\n      const gtmId = integrations.googleTagManagerId;\n      const script = document.createElement('script');\n      script.textContent = `\n        (function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({'gtm.start':\n        new Date().getTime(),event:'gtm.js'});var f=d.getElementsByTagName(s)[0],\n        j=d.createElement(s),dl=l!='dataLayer'?'&l='+l:'';j.async=true;j.src=\n        'https://www.googletagmanager.com/gtm.js?id='+i+dl;f.parentNode.insertBefore(j,f);\n        })(window,document,'script','dataLayer','${gtmId}');\n      `;\n      document.head.appendChild(script);\n\n      // GTM noscript fallback\n      const noscript = document.createElement('noscript');\n      const iframe = document.createElement('iframe');\n      iframe.src = `https://www.googletagmanager.com/ns.html?id=${gtmId}`;\n      iframe.height = '0';\n      iframe.width = '0';\n      iframe.style.display = 'none';\n      iframe.style.visibility = 'hidden';\n      noscript.appendChild(iframe);\n      document.body.prepend(noscript);\n    }\n\n    // --- Facebook Pixel ---\n    if (integrations.facebookPixelId) {\n      const fbId = integrations.facebookPixelId;\n      const script = document.createElement('script');\n      script.textContent = `\n        !function(f,b,e,v,n,t,s)\n        {if(f.fbq)return;n=f.fbq=function(){n.callMethod?\n        n.callMethod.apply(n,arguments):n.queue.push(arguments)};\n        if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';\n        n.queue=[];t=b.createElement(e);t.async=!0;\n        t.src=v;s=b.getElementsByTagName(e)[0];\n        s.parentNode.insertBefore(t,s)}(window, document,'script',\n        'https://connect.facebook.net/en_US/fbevents.js');\n        fbq('init', '${fbId}');\n        fbq('track', 'PageView');\n      `;\n      document.head.appendChild(script);\n    }\n\n    // --- Hotjar ---\n    if (integrations.hotjarId) {\n      const hjId = integrations.hotjarId;\n      const script = document.createElement('script');\n      script.textContent = `\n        (function(h,o,t,j,a,r){\n          h.hj=h.hj||function(){(h.hj.q=h.hj.q||[]).push(arguments)};\n          h._hjSettings={hjid:${hjId},hjsv:6};\n          a=o.getElementsByTagName('head')[0];\n          r=o.createElement('script');r.async=1;\n          r.src=t+h._hjSettings.hjid+j+h._hjSettings.hjsv;\n          a.appendChild(r);\n        })(window,document,'https://static.hotjar.com/c/hotjar-','.js?sv=');\n      `;\n      document.head.appendChild(script);\n    }\n\n    // --- Custom head scripts ---\n    if (integrations.customHeadScripts) {\n      const container = document.createElement('div');\n      container.innerHTML = integrations.customHeadScripts;\n      Array.from(container.children).forEach(child => {\n        document.head.appendChild(child.cloneNode(true));\n      });\n    }\n\n    // --- Custom body scripts ---\n    if (integrations.customBodyScripts) {\n      const container = document.createElement('div');\n      container.innerHTML = integrations.customBodyScripts;\n      Array.from(container.children).forEach(child => {\n        document.body.appendChild(child.cloneNode(true));\n      });\n    }\n  }, [integrations]);\n\n  /**\n   * Track a custom event (works with GA4 and Facebook Pixel).\n   */\n  const trackEvent = useCallback((eventName, params = {}) => {\n    // GA4\n    if (window.gtag) {\n      window.gtag('event', eventName, params);\n    }\n\n    // Facebook Pixel\n    if (window.fbq) {\n      window.fbq('trackCustom', eventName, params);\n    }\n\n    // GTM dataLayer\n    if (window.dataLayer) {\n      window.dataLayer.push({\n        event: eventName,\n        ...params,\n      });\n    }\n  }, []);\n\n  /**\n   * Track a page view (called on route change in SPA).\n   */\n  const trackPageView = useCallback((path, title) => {\n    if (window.gtag) {\n      window.gtag('event', 'page_view', {\n        page_path: path,\n        page_title: title,\n      });\n    }\n    if (window.fbq) {\n      window.fbq('track', 'PageView');\n    }\n  }, []);\n\n  return { trackEvent, trackPageView };\n};\n\nexport default useAnalytics;\n","import React from 'react';\n\n// Import all section components\nimport Hero from '../components/display/Hero';\nimport ContentBlock from '../components/content/ContentBlock';\nimport FeatureGrid from '../components/display/FeatureGrid';\nimport FormSection from '../components/forms/FormSection';\nimport CTABanner from '../components/display/CTABanner';\nimport Testimonials from '../components/display/Testimonials';\nimport PricingTable from '../components/display/PricingTable';\nimport FAQAccordion from '../components/display/FAQAccordion';\nimport ImageGallery from '../components/display/ImageGallery';\nimport VideoEmbed from '../components/display/VideoEmbed';\nimport DataTable from '../components/data/DataTable';\nimport StatsCounter from '../components/display/StatsCounter';\nimport Timeline from '../components/display/Timeline';\nimport TabsSection from '../components/display/TabsSection';\nimport CustomHTML from '../components/content/CustomHTML';\n\n/**\n * Component Registry - Maps Strapi component names to React components.\n *\n * Supports both naming conventions:\n *   - layout.*  (Strapi actual component category — from dynamic zone)\n *   - sections.* (legacy naming — for backward compatibility)\n *\n * This means the same library works regardless of how the Strapi\n * schema names its component categories.\n */\nconst COMPONENT_REGISTRY = {\n  // Primary: layout.* — matches Strapi schema\n  'layout.hero': Hero,\n  'layout.content': ContentBlock,\n  'layout.feature-grid': FeatureGrid,\n  'layout.form': FormSection,\n  'layout.cta-banner': CTABanner,\n  'layout.testimonials': Testimonials,\n  'layout.pricing-table': PricingTable,\n  'layout.faq-accordion': FAQAccordion,\n  'layout.image-gallery': ImageGallery,\n  'layout.video-embed': VideoEmbed,\n  'layout.data-table': DataTable,\n  'layout.stats-counter': StatsCounter,\n  'layout.timeline': Timeline,\n  'layout.tabs-section': TabsSection,\n  'layout.custom-html': CustomHTML,\n\n  // Legacy: sections.* — backward compatibility\n  'sections.hero': Hero,\n  'sections.content-block': ContentBlock,\n  'sections.feature-grid': FeatureGrid,\n  'sections.form-section': FormSection,\n  'sections.cta-banner': CTABanner,\n  'sections.testimonials': Testimonials,\n  'sections.pricing-table': PricingTable,\n  'sections.faq-accordion': FAQAccordion,\n  'sections.image-gallery': ImageGallery,\n  'sections.video-embed': VideoEmbed,\n  'sections.data-table': DataTable,\n  'sections.stats-counter': StatsCounter,\n  'sections.timeline': Timeline,\n  'sections.tabs-section': TabsSection,\n  'sections.custom-html': CustomHTML,\n};\n\n/**\n * Normalize a component type string for CSS class naming.\n * Strips any category prefix (layout., sections., etc.)\n */\nconst normalizeType = (type) => {\n  if (!type) return 'unknown';\n  const parts = type.split('.');\n  return parts[parts.length - 1];\n};\n\n/**\n * ComponentRenderer - Renders a single Strapi component\n */\nexport const ComponentRenderer = ({\n  component,\n  componentOverrides = {},\n  onFormSubmit,\n  sectionIndex = 0,\n  className = ''\n}) => {\n  if (!component) return null;\n\n  const componentType = component.__component;\n\n  // Check for custom override first, then registry\n  const Component = componentOverrides[componentType] || COMPONENT_REGISTRY[componentType];\n\n  if (!Component) {\n    if (process.env.NODE_ENV === 'development') {\n      console.warn(`Unknown component type: ${componentType}`);\n      return (\n        <div className=\"component-unknown\" style={{\n          padding: '2rem',\n          background: '#fee',\n          border: '1px solid #f00',\n          margin: '1rem 0'\n        }}>\n          Unknown component: {componentType}\n        </div>\n      );\n    }\n    return null;\n  }\n\n  // Pass component data as props, excluding __component and id\n  const { __component, id, ...props } = component;\n\n  return (\n    <div\n      className={`component-section component-${normalizeType(componentType)} ${className}`}\n      data-component-id={id}\n      data-component-type={componentType}\n      data-section-index={sectionIndex}\n    >\n      <Component {...props} sectionIndex={sectionIndex} onFormSubmit={onFormSubmit} />\n    </div>\n  );\n};\n\n/**\n * Register a custom component (supports both naming conventions)\n */\nexport const registerComponent = (name, component) => {\n  COMPONENT_REGISTRY[name] = component;\n};\n\n/**\n * Get all registered components\n */\nexport const getRegisteredComponents = () => {\n  return { ...COMPONENT_REGISTRY };\n};\n\nexport default ComponentRenderer;\n","import React from 'react';\nimport { useForm } from '../hooks/useForm';\nimport clsx from 'clsx';\n\n// Import form field components\nimport TextField from '../components/forms/TextField';\nimport TextArea from '../components/forms/TextArea';\nimport Select from '../components/forms/Select';\nimport Checkbox from '../components/forms/Checkbox';\nimport RadioGroup from '../components/forms/RadioGroup';\nimport DatePicker from '../components/forms/DatePicker';\nimport FileUpload from '../components/forms/FileUpload';\nimport Button from '../components/forms/Button';\n\n/**\n * Field Registry - Maps Strapi field types to React components\n */\nconst FIELD_REGISTRY = {\n  text: TextField,\n  email: TextField,\n  password: TextField,\n  number: TextField,\n  tel: TextField,\n  url: TextField,\n  textarea: TextArea,\n  select: Select,\n  multiselect: Select,\n  checkbox: Checkbox,\n  radio: RadioGroup,\n  date: DatePicker,\n  time: DatePicker,\n  datetime: DatePicker,\n  file: FileUpload,\n  hidden: ({ name, value }) => <input type=\"hidden\" name={name} value={value} />,\n};\n\n/**\n * FormRenderer - Renders a dynamic form from Strapi form definition\n */\nexport const FormRenderer = ({\n  formId,\n  fields,\n  submitButtonText = 'Submit',\n  successMessage = 'Thank you for your submission!',\n  errorMessage = 'Something went wrong. Please try again.',\n  onSubmit,\n  submitAction,\n  webhookUrl,\n  emailTo,\n  className = '',\n  fieldOverrides = {},\n}) => {\n  const {\n    values,\n    errors,\n    touched,\n    submitting,\n    submitted,\n    handleChange,\n    handleBlur,\n    handleSubmit,\n    reset,\n    isFieldVisible,\n  } = useForm(fields, {\n    onSubmit: async (formValues) => {\n      // Handle different submit actions\n      switch (submitAction) {\n        case 'webhook':\n          await fetch(webhookUrl, {\n            method: 'POST',\n            headers: { 'Content-Type': 'application/json' },\n            body: JSON.stringify(formValues),\n          });\n          break;\n        case 'email':\n          // Would typically call a backend endpoint\n          console.log('Email submission to:', emailTo, formValues);\n          break;\n        case 'api':\n          if (onSubmit) {\n            await onSubmit(formValues);\n          }\n          break;\n        default:\n          // Store locally or call custom handler\n          if (onSubmit) {\n            await onSubmit(formValues);\n          }\n      }\n    },\n    validateOnChange: true,\n  });\n\n  if (submitted) {\n    return (\n      <div className=\"form-success\" style={{\n        padding: '2rem',\n        textAlign: 'center',\n        background: '#d4edda',\n        borderRadius: '8px',\n        color: '#155724',\n      }}>\n        <p>{successMessage}</p>\n        <button \n          onClick={reset}\n          style={{\n            marginTop: '1rem',\n            padding: '0.5rem 1rem',\n            cursor: 'pointer',\n          }}\n        >\n          Submit Another\n        </button>\n      </div>\n    );\n  }\n\n  return (\n    <form \n      id={formId}\n      className={clsx('dynamic-form', className)}\n      onSubmit={handleSubmit}\n      noValidate\n    >\n      <div className=\"form-fields\" style={{\n        display: 'grid',\n        gap: '1rem',\n        gridTemplateColumns: 'repeat(12, 1fr)',\n      }}>\n        {fields.map((field) => {\n          if (!isFieldVisible(field)) return null;\n\n          const FieldComponent = fieldOverrides[field.type] || FIELD_REGISTRY[field.type] || TextField;\n          \n          // Calculate grid column span\n          const widthMap = {\n            full: 12,\n            half: 6,\n            third: 4,\n            quarter: 3,\n          };\n          const colSpan = widthMap[field.width] || 12;\n\n          return (\n            <div \n              key={field.name}\n              className={clsx('form-field', `field-${field.type}`)}\n              style={{ gridColumn: `span ${colSpan}` }}\n            >\n              <FieldComponent\n                {...field}\n                value={values[field.name]}\n                error={touched[field.name] ? errors[field.name] : null}\n                onChange={(value) => handleChange(field.name, value)}\n                onBlur={() => handleBlur(field.name)}\n              />\n            </div>\n          );\n        })}\n      </div>\n\n      <div className=\"form-actions\" style={{ marginTop: '1.5rem' }}>\n        <Button\n          type=\"submit\"\n          variant=\"primary\"\n          size=\"large\"\n          disabled={submitting}\n          text={submitting ? 'Submitting...' : submitButtonText}\n        />\n      </div>\n    </form>\n  );\n};\n\n/**\n * Register a custom field component\n */\nexport const registerField = (type, component) => {\n  FIELD_REGISTRY[type] = component;\n};\n\nexport default FormRenderer;\n\n","import React, { useEffect } from 'react';\nimport ComponentRenderer from './ComponentRenderer';\n\n/**\n * PageRenderer - Renders a complete page from Strapi page data.\n *\n * Works with both Strapi data shapes:\n *   - { attributes: { title, layout: [...] } }   (Strapi v5 REST)\n *   - { title, layout: [...] }                    (flat / pre-extracted)\n *   - { attributes: { title, sections: [...] } }  (legacy)\n */\nexport const PageRenderer = ({\n  page,\n  componentOverrides = {},\n  onFormSubmit,\n  layout: LayoutComponent,\n  loading = false,\n  error = null,\n  notFound = null,\n  loadingComponent: LoadingComponent,\n  errorComponent: ErrorComponent,\n  scrollToTop = true,\n  className = '',\n}) => {\n  // Scroll to top when page changes\n  useEffect(() => {\n    if (scrollToTop && page) {\n      window.scrollTo(0, 0);\n    }\n  }, [page, scrollToTop]);\n\n  // Handle loading state\n  if (loading) {\n    if (LoadingComponent) {\n      return <LoadingComponent />;\n    }\n    return (\n      <div className=\"page-loading\" style={{\n        display: 'flex',\n        justifyContent: 'center',\n        alignItems: 'center',\n        minHeight: '50vh'\n      }}>\n        <div className=\"loading-spinner\">Loading...</div>\n      </div>\n    );\n  }\n\n  // Handle error state\n  if (error) {\n    if (ErrorComponent) {\n      return <ErrorComponent error={error} />;\n    }\n    return (\n      <div className=\"page-error\" style={{\n        padding: '2rem',\n        textAlign: 'center',\n        minHeight: '50vh'\n      }}>\n        <h2>Error Loading Page</h2>\n        <p>{error.message || 'An unexpected error occurred'}</p>\n      </div>\n    );\n  }\n\n  // Handle not found\n  if (!page) {\n    if (notFound) {\n      return notFound;\n    }\n    return (\n      <div className=\"page-not-found\" style={{\n        padding: '2rem',\n        textAlign: 'center',\n        minHeight: '50vh'\n      }}>\n        <h1>404</h1>\n        <p>Page not found</p>\n      </div>\n    );\n  }\n\n  const attributes = page.attributes || page;\n  // Support both \"layout\" (current Strapi schema) and \"sections\" (legacy)\n  const sections = attributes.layout || attributes.sections || [];\n  const { title, metadata, metaTitle, metaDescription } = attributes;\n\n  // Build page content\n  const pageContent = (\n    <div\n      className={`page-content ${className}`}\n      data-page-id={page.id || page.documentId}\n    >\n      <main className=\"page-sections\">\n        {sections.map((section, index) => (\n          <ComponentRenderer\n            key={section.id || index}\n            component={section}\n            componentOverrides={componentOverrides}\n            onFormSubmit={onFormSubmit}\n            sectionIndex={index}\n          />\n        ))}\n      </main>\n    </div>\n  );\n\n  // Wrap in layout if provided\n  if (LayoutComponent) {\n    return (\n      <LayoutComponent\n        page={page}\n        title={metaTitle || metadata?.title || title}\n        description={metaDescription || metadata?.description}\n      >\n        {pageContent}\n      </LayoutComponent>\n    );\n  }\n\n  return pageContent;\n};\n\n/**\n * Helper to get page meta data\n */\nexport const getPageMeta = (page) => {\n  if (!page) return null;\n\n  const attrs = page.attributes || page;\n  const meta = attrs.metadata || {};\n  return {\n    title: meta.title || attrs.metaTitle || attrs.title,\n    description: meta.description || attrs.metaDescription,\n    keywords: meta.keywords || attrs.metaKeywords,\n    ogImage: attrs.ogImage?.data?.attributes?.url,\n  };\n};\n\nexport default PageRenderer;\n"],"names":["Info","Map","Button","_ref","text","url","link","_ref$type","type","_ref$variant","variant","_ref$size","size","icon","_ref$iconPosition","iconPosition","_ref$openInNewTab","openInNewTab","scrollTarget","onClick","_ref$disabled","disabled","_ref$style","style","_ref$className","className","resolvedUrl","IconComponent","Icons","sizeStyles","small","padding","fontSize","medium","large","variantStyles","primary","background","color","border","secondary","outline","ghost","danger","success","buttonStyle","_objectSpread","display","alignItems","justifyContent","gap","borderRadius","fontWeight","cursor","opacity","transition","textDecoration","handleClick","e","preventDefault","element","document","querySelector","scrollIntoView","behavior","content","React","createElement","Fragment","href","target","undefined","rel","clsx","concat","Hero","_backgroundImage$data","title","subtitle","cta","secondaryCta","_ref$gradientFrom","gradientFrom","_ref$gradientTo","gradientTo","_ref$minHeight","minHeight","primaryButton","secondaryButton","backgroundImage","backgroundVideo","_ref$alignment","alignment","height","_ref$overlay","overlay","overlayCo